const badgeTone = (value = "") => {
  const v = String(value).toLowerCase();
  if (["approved","active","available","open","completed","configured","qualified","ready","accepted","high"].includes(v)) return "green";
  if (["pending","processing","scheduled","claimed","review","medium","partial","unverified"].includes(v)) return "amber";
  if (["inactive","cancelled","lost","failed","critical","high risk","expired"].includes(v)) return "red";
  return "cyan";
};
const pill = (value) => `<span class="pill ${badgeTone(value)}">${escapeHtml(titleCase(value || "unknown"))}</span>`;
const yesNo = (value) => value ? "Yes" : "No";
