const metric = (label, value, note, icon = "FN") => `<article class="card metric-card"><div class="metric-icon">${escapeHtml(icon)}</div><div class="metric-label">${escapeHtml(label)}</div><div class="metric-value">${escapeHtml(String(value))}</div><div class="metric-note">${escapeHtml(note)}</div></article>`;
const progress = (current, target) => {
  const pct = target ? clamp((Number(current) / Number(target)) * 100, 0, 100) : 0;
  return `<div class="progress" title="${formatNumber(current)} / ${formatNumber(target)}"><span style="--progress:${pct}%"></span></div>`;
};

