export function setLivePatch(version) {
  const next = String(version || "").trim();
  if (!/^\d+(?:\.[0-9A-Za-z]+){1,3}$/.test(next)) return false;
  LIVE_PATCH = next;
  config.livePatch = next;
  for (const def of Object.values(moduleDefs)) {
    const versionField = def.fields?.find((item) => item.name === "game_version");
    if (versionField) versionField.default = next;
  }
  return true;
}

async function loadProfiles() { state.profiles = await db.profiles(); return state.profiles; }
function formatCell(key, value, row) {
  if (value == null || value === "") return `<span class="muted">—</span>`;
  if (["member_id","owner_id","instructor_id","commander_id","reported_by","requester_id","responder_id","hauler_id","claimed_by","seller_id"].includes(key)) return escapeHtml(profileName(value));
  if (key.includes("_at") || key === "deadline" || key === "expires_at" || key === "collection_deadline") return escapeHtml(formatDate(value));
  if (key.includes("price") || key.includes("cost") || key.includes("reward_auec") || key === "amount") return escapeHtml(formatCredits(value));
  if (["status","priority","confidence","risk_level","threat_level","severity","classification","warehouse_status","reserve_status","level"].includes(key)) return pill(value);
  if (["org_owned","loadout_imprinted","voice_available","active"].includes(key)) return value ? `<span class="positive">Yes</span>` : `<span class="negative">No</span>`;
  if (key === "quantity") return `${formatNumber(value)} ${escapeHtml(row.unit || "")}`;
  if (key === "current_quantity" && row.target_quantity) return `${formatNumber(value)} / ${formatNumber(row.target_quantity)}${progress(value,row.target_quantity)}`;
  if (key === "fuel_percent" || key === "hull_percent") return `${formatNumber(value)}%${progress(value,100)}`;
  return escapeHtml(String(value));
}

function canAdd(def, profile) { return Boolean(def.memberCreate || canManage(profile, def.manage)); }
function canEdit(def, profile, row) {
  if (canManage(profile, def.manage)) return true;
  const memberOwnedFields = {
    market_listings: "seller_id",
    crew_availability: "member_id",
    fleet_ships: "owner_id",
    rescue_requests: "requester_id"
  };
  const ownerField = memberOwnedFields[def.table];
  return Boolean(ownerField && row[ownerField] === profile.id);
}
function normaliseFormValue(fieldDef, form) {
  const input = form.elements[fieldDef.name];
  if (!input) return fieldDef.default ?? "";
  if (fieldDef.type === "checkbox") return input.checked;
  if (fieldDef.type === "number") return Number(input.value || 0);
  if (fieldDef.type === "datetime-local") return input.value ? new Date(input.value).toISOString() : null;
  return input.value.trim();
}
function formControl(fieldDef, value = "") {
  const id = `field-${fieldDef.name}`;
  const safe = value == null ? "" : value;
  if (fieldDef.type === "hidden") return `<input type="hidden" name="${fieldDef.name}" value="${escapeHtml(safe || fieldDef.default || "")}">`;
  if (fieldDef.type === "textarea") return `<label class="field full-span" for="${id}">${escapeHtml(fieldDef.label)}<textarea id="${id}" name="${fieldDef.name}" ${fieldDef.required ? "required" : ""}>${escapeHtml(safe)}</textarea></label>`;
  if (fieldDef.type === "select") return `<label class="field" for="${id}">${escapeHtml(fieldDef.label)}<select id="${id}" name="${fieldDef.name}">${fieldDef.options.map((option) => `<option value="${escapeHtml(option)}" ${String(option) === String(safe || fieldDef.default) ? "selected" : ""}>${escapeHtml(titleCase(option))}</option>`).join("")}</select></label>`;
  if (fieldDef.type === "profile") return `<label class="field" for="${id}">${escapeHtml(fieldDef.label)}<select id="${id}" name="${fieldDef.name}"><option value="">Unassigned</option>${state.profiles.map((member) => `<option value="${member.id}" ${member.id === safe ? "selected" : ""}>${escapeHtml(member.display_name)}</option>`).join("")}</select></label>`;
  if (fieldDef.type === "checkbox") return `<label class="field checkbox-field" for="${id}"><input id="${id}" name="${fieldDef.name}" type="checkbox" ${safe ? "checked" : ""}> ${escapeHtml(fieldDef.label)}</label>`;
  let inputValue = safe;
  if (fieldDef.type === "datetime-local" && safe) inputValue = new Date(safe).toISOString().slice(0,16);
  return `<label class="field" for="${id}">${escapeHtml(fieldDef.label)}<input id="${id}" name="${fieldDef.name}" type="${fieldDef.type || "text"}" value="${escapeHtml(inputValue || fieldDef.default || "")}" ${fieldDef.required ? "required" : ""}></label>`;
}
async function openRecordForm(pageId, def, profile, existing = null, refresh) {
  const editing = Boolean(existing);
  const modal = openModal(`<button class="icon-button close-button" data-close-modal aria-label="Close">×</button><p class="eyebrow">${editing ? "EDIT RECORD" : "NEW RECORD"}</p><h2>${editing ? "Update" : "Add"} ${escapeHtml(def.title)}</h2><form id="record-form"><div class="form-grid">${def.fields.map((f) => formControl(f, existing?.[f.name])).join("")}</div><div class="form-actions"><button type="button" class="button ghost" data-close-modal>Cancel</button><button type="submit" class="button primary">${editing ? "Save changes" : "Add record"}</button></div></form>`, true);
  $$('[data-close-modal]', modal.card).forEach((button) => button.addEventListener("click", modal.close));
  $("#record-form", modal.card).addEventListener("submit", async (event) => {
    event.preventDefault(); const button = event.submitter; setLoading(button, true, editing ? "Saving…" : "Adding…");
    try {
      const payload = Object.fromEntries(def.fields.map((f) => [f.name, normaliseFormValue(f, event.currentTarget)]));
      if (!editing) {
        if (def.pendingOnMember && !canManage(profile, def.manage)) { payload.status = "pending"; payload.confidence = payload.confidence || "pending"; }
        if (pageId === "crew") payload.member_id = profile.id;
        if (pageId === "fleet") payload.owner_id = profile.id;
        if (pageId === "market") payload.seller_id = profile.id;
        if (pageId === "rescue") payload.requester_id = profile.id;
        if (["intel","incidents"].includes(pageId)) payload.reported_by = profile.id;
        if (["knowledge","mining","salvaging"].includes(pageId)) payload.submitted_by = profile.id;
        if (pageId === "contracts") payload.created_by = profile.id;
        await db.create(def.table, payload);
      } else await db.update(def.table, existing.id, payload);
      modal.close(); toast(editing ? "Record updated." : "Record added.", "success"); await refresh();
    } catch (error) { toast(error.message, "error", 6000); }
    finally { setLoading(button, false); }
  });
}

async function renderDirectoryPage(content, profile, pageId, refreshOverride = null) {
  const def = moduleDefs[pageId]; await loadProfiles();
  let rows = liveRows(await db.list(def.table, { order: "updated_at" }));
  const [flags, watches] = await Promise.all([
    db.list("data_flags", { order: "created_at" }).catch(() => []),
    db.list("watchlists", { order: "created_at" }).catch(() => [])
  ]);
  const watchedIds = new Set(watches.filter((w) => w.entity_type === def.table).map((w) => String(w.entity_id)));
  const refresh = refreshOverride || (() => renderDirectoryPage(content, profile, pageId));
  const quarantineCount = (await db.list(def.table, { order: null })).length - rows.length;
  content.innerHTML = `${pageHero(def.title, def.description)}
    ${quarantineCount ? `<div class="notice warning"><strong>${quarantineCount} record(s) hidden.</strong> They do not match Alpha ${escapeHtml(LIVE_PATCH)} LIVE.</div>` : ""}
    ${header(def.title, `${rows.length} LIVE-compatible record${rows.length === 1 ? "" : "s"}.`, canAdd(def, profile) ? `<button id="add-record" class="button primary">${def.memberCreate && !canManage(profile, def.manage) ? "Submit" : "Add"} record</button>` : "")}
    <div class="toolbar"><input id="module-filter" type="search" placeholder="Filter this page…"><select id="status-filter"><option value="">All statuses</option>${[...new Set(rows.map((r) => r.status).filter(Boolean))].map((s) => `<option value="${escapeHtml(s)}">${escapeHtml(titleCase(s))}</option>`).join("")}</select></div>
    <div class="table-wrap"><table><thead><tr>${def.columns.map(([,label]) => `<th>${escapeHtml(label)}</th>`).join("")}<th>Actions</th></tr></thead><tbody id="module-rows"></tbody></table></div>`;

  const renderRows = () => {
    const q = $("#module-filter").value.toLowerCase(); const status = $("#status-filter").value;
    const filtered = rows.filter((row) => (!status || row.status === status) && (!q || JSON.stringify(row).toLowerCase().includes(q)));
    $("#module-rows").innerHTML = filtered.length ? filtered.map((row) => `<tr>${def.columns.map(([key]) => `<td>${formatCell(key,row[key],row)}</td>`).join("")}<td><div class="table-actions">
      ${def.actions === "claim" && row.status === "open" ? `<button class="button small" data-claim="${row.id}">Claim</button>` : ""}
      ${def.actions === "confirm" && row.status !== "rejected" ? `<button class="button small" data-confirm="${row.id}">Confirm LIVE</button>` : ""}
      ${def.actions === "respond" && row.status === "open" ? `<button class="button small" data-respond="${row.id}">Respond</button>` : ""}
      <button class="button small ghost" data-watch="${row.id}" data-watch-name="${escapeHtml(row.title||row.name||row.item_name||row.material_name||row.location_name||row.id)}">${watchedIds.has(String(row.id)) ? "Unwatch" : "Watch"}</button>
      <button class="button small ghost" data-flag="${row.id}" data-flag-name="${escapeHtml(row.title||row.name||row.item_name||row.material_name||row.location_name||row.id)}">Flag${flags.filter((f)=>f.target_table===def.table&&String(f.target_id)===String(row.id)&&["open","reviewing"].includes(f.status)).length ? ` (${flags.filter((f)=>f.target_table===def.table&&String(f.target_id)===String(row.id)&&["open","reviewing"].includes(f.status)).length})` : ""}</button>
      ${canEdit(def, profile, row) ? `<button class="button small ghost" data-edit="${row.id}">Edit</button>` : ""}
      ${canManage(profile, def.manage) ? `<button class="button small danger" data-delete="${row.id}">Delete</button>` : ""}
    </div></td></tr>`).join("") : `<tr><td colspan="${def.columns.length + 1}">${emptyState("No matching records", "Try a different filter or add the first record.")}</td></tr>`;
    $$('[data-watch]').forEach((button) => button.addEventListener("click", async () => {
      try {
        const result = await db.rpc("toggle_watchlist", { entity_type: def.table, entity_id: button.dataset.watch, entity_name: button.dataset.watchName, alert_types: ["changed","flagged","available"] });
        toast(result.watching ? "Added to your watchlist." : "Removed from your watchlist.", "success");
        await refresh();
      } catch (error) { toast(error.message, "error", 6000); }
    }));
    $$('[data-flag]').forEach((button) => button.addEventListener("click", () => {
      const modal = openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">ACCURACY REPORT</p><h2>Flag incorrect information</h2><p class="fine-print">Explain what is wrong and, where possible, include the corrected information or evidence.</p><form id="flag-form" class="stack-form"><label>Reason<select name="reason"><option>Incorrect location</option><option>Outdated LIVE information</option><option>Incorrect price</option><option>Incorrect item details</option><option>Incorrect blueprint materials</option><option>Incorrect mining location</option><option>Incorrect salvage information</option><option>Item or location removed</option><option>Duplicate record</option><option>Other</option></select></label><label>What is wrong?<textarea name="explanation" rows="5" required></textarea></label><label>Suggested correction<textarea name="suggested" rows="3"></textarea></label><label>Evidence link<input name="evidence" type="url" placeholder="Screenshot, clip or source URL"></label><button class="button primary">Submit flag</button></form>`);
      $("#flag-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;try{await db.create("data_flags",{target_table:def.table,target_id:button.dataset.flag,target_name:button.dataset.flagName,reason:f.reason.value,explanation:f.explanation.value,suggested_correction:f.suggested.value,evidence_url:f.evidence.value,status:"open"});modal.close();toast("Accuracy flag submitted to Officers.","success");await refresh();}catch(error){toast(error.message,"error",6000);}});
    }));
    $$('[data-edit]').forEach((button) => button.addEventListener("click", () => openRecordForm(pageId, def, profile, rows.find((r) => r.id === button.dataset.edit), refresh)));
    $$('[data-delete]').forEach((button) => button.addEventListener("click", async () => { if (!confirm("Delete this record?")) return; await db.remove(def.table, button.dataset.delete); toast("Record deleted.", "success"); await refresh(); }));
    $$('[data-claim]').forEach((button) => button.addEventListener("click", async () => {
      try { await db.rpc("claim_org_job", { target_table: def.table, target_id: button.dataset.claim }); toast("Job claimed.", "success"); await refresh(); }
      catch (error) { toast(error.message, "error", 6000); }
    }));
    $$('[data-confirm]').forEach((button) => button.addEventListener("click", async () => {
      try { await db.rpc("confirm_live_record", { target_table: def.table, target_id: button.dataset.confirm, live_version: LIVE_PATCH }); toast(`Confirmed on Alpha ${LIVE_PATCH} LIVE.`, "success"); await refresh(); }
      catch (error) { toast(error.message, "error", 6000); }
    }));
    $$('[data-respond]').forEach((button) => button.addEventListener("click", async () => {
      try { await db.rpc("accept_rescue_request", { target_request: button.dataset.respond }); toast("Response accepted.", "success"); await refresh(); }
      catch (error) { toast(error.message, "error", 6000); }
    }));
  };
  $("#module-filter").addEventListener("input", renderRows); $("#status-filter").addEventListener("change", renderRows); renderRows();
  $("#add-record")?.addEventListener("click", () => openRecordForm(pageId, def, profile, null, refresh));
}

function injectManagedPageContent(content, pageId) {
  const blocks = (config.managedPageContent || [])
    .filter((row) => row.enabled !== false && row.page_id === pageId)
    .sort((a, b) => String(a.section_key || "").localeCompare(String(b.section_key || "")));
  if (!blocks.length) return;
  const html = blocks.map((row) => `<section class="card pad managed-content-block" data-section-key="${escapeHtml(row.section_key || "content")}">${row.title ? `<h2>${escapeHtml(row.title)}</h2>` : ""}<div class="managed-content-body">${escapeHtml(row.body || "").replaceAll("\n", "<br>")}</div></section>`).join("");
  const hero = $(".page-hero", content);
  if (hero) hero.insertAdjacentHTML("afterend", html);
  else content.insertAdjacentHTML("afterbegin", html);
}

export async function renderPage(pageId, profile, context = {}) {
  const content = $("#page-content"); state.query = context.query ?? state.query;
  content.innerHTML = `<div class="grid cols-3"><div class="skeleton"></div><div class="skeleton"></div><div class="skeleton"></div></div>`;
  if (pageId === "sync" && !profile?.capabilities?.edit_game_data) { content.innerHTML = emptyState("Restricted area", "Officer access or above is required."); return; }
  if (pageId === "admin" && !profile?.capabilities?.approve_applications) { content.innerHTML = emptyState("Restricted area", "Officer or authorised admin access is required."); return; }
  if (pageId === "backup" && !profile?.capabilities?.manage_site) { content.innerHTML = emptyState("Restricted area", "Site administration permission is required."); return; }
  try {
    const custom = {
      dashboard: renderDashboard, search: renderSearch, notifications: renderNotifications, warehouse: renderWarehouse,
      workorders: renderWorkOrders, crafting: renderCrafting, trade: renderTrade, knowledge: renderKnowledge, catalog: renderCatalog,
      salvaging: renderSalvaging, auctions: renderAuctions, treasury: renderTreasury, operations: renderOperations,
      members: renderMembers, orgchart: renderOrgChart, knowledgebase: renderKnowledgeBase, watchlist: renderWatchlist, verification: renderVerification, sync: renderSync, admin: renderAdmin, backup: renderBackup
    }[pageId];
    if (custom) await custom(content, profile, context); else if (moduleDefs[pageId]) await renderDirectoryPage(content, profile, pageId); else content.innerHTML = emptyState("Module unavailable", "This page has not been connected yet.");
    injectManagedPageContent(content, pageId);
  } catch (error) { console.error(error); content.innerHTML = `<div class="notice danger"><strong>Module failed to load.</strong><br>${escapeHtml(error.message)}</div>`; }
}

async function renderDashboard(content, profile) {
  const [profiles, warehouse, workorders, operations, fleet, rescue, notifications, refinery, intel] = await Promise.all([
    loadProfiles(), db.list("warehouse_items"), db.list("work_orders"), db.list("operations"), db.list("fleet_ships"), db.list("rescue_requests"), db.list("notifications"), db.list("refinery_jobs"), db.list("intel_reports")
  ]);
  state.warehouse = warehouse;
  const shortages = warehouse.filter((item) => Number(item.quantity || 0) - Number(item.reserved_quantity || 0) < Number(item.minimum_stock || 0));
  const upcoming = liveRows(operations).filter((op) => new Date(op.start_at) > new Date() && !["cancelled","completed"].includes(op.status)).slice(0,4);
  const emergencies = liveRows(rescue).filter((item) => ["open","accepted","responding"].includes(item.status));
  const unread = notifications.filter((n) => n.member_id === profile.id && !n.read_at);
  const openOrders = liveRows(workorders).filter((w) => !["completed","cancelled"].includes(w.status));
  const readyRefinery = liveRows(refinery).filter((j) => j.status === "ready" || (j.completes_at && new Date(j.completes_at) <= new Date()));
  const activeIntel = liveRows(intel).filter((i) => ["active","unverified"].includes(i.status));
  content.innerHTML = `${pageHero("Free Navy command network", "One connected operational picture: stock, jobs, crews, ships, threats and LIVE patch health.", `<div class="hero-badges"><span class="pill green">Alpha ${escapeHtml(LIVE_PATCH)} LIVE</span><span class="pill cyan">${escapeHtml(rankLabel(profile.rank))}</span></div>`)}
    <div class="grid cols-4">
      ${metric("Active members", profiles.filter((p) => p.status === "active").length, `${profiles.length} total records`, "CREW")}
      ${metric("Your points", formatNumber(profile.points_balance), "Available after reserved bids", "PTS")}
      ${metric("Fleet ready", fleet.filter((s) => s.status === "available").length, `${fleet.length} registered ships`, "FLEET")}
      ${metric("Open work orders", openOrders.length, `${openOrders.filter((w) => w.priority === "high" || w.priority === "critical").length} high priority`, "TASK")}
    </div>
    ${emergencies.length ? `<section class="card pad emergency-card">${header("Active emergency requests", "Medical and recovery calls take priority.", `<button class="button danger" data-go="rescue">Open response centre</button>`)}<div class="list">${emergencies.map((r) => `<div class="list-item"><div><strong>${escapeHtml(r.title)}</strong><small>${escapeHtml(r.system_name)} · ${escapeHtml(r.location_name)} · ${escapeHtml(r.notes || "")}</small></div>${pill(r.threat_level)}</div>`).join("")}</div></section>` : ""}
    <div class="grid cols-2 dashboard-grid">
      <section class="card pad">${header("Upcoming operations", "Scheduled activities requiring crews and assets.", `<button class="button small ghost" data-go="operations">Open operations</button>`)}<div class="list">${upcoming.length ? upcoming.map((op) => `<div class="list-item"><div><strong>${escapeHtml(op.title)}</strong><small>${formatDate(op.start_at)} · ${escapeHtml(op.location)}</small></div>${pill(op.status)}</div>`).join("") : emptyState("No operations scheduled", "An officer can create the next operation.")}</div></section>
      <section class="card pad">${header("Logistics warnings", "Short stock, refinery collections and active work orders.", `<button class="button small ghost" data-go="workorders">Open work orders</button>`)}<div class="list">
        ${shortages.slice(0,3).map((item) => `<div class="list-item"><div><strong>${escapeHtml(item.name)}</strong><small>${formatNumber(Number(item.quantity)-Number(item.reserved_quantity))} ${escapeHtml(item.unit)} available; minimum ${formatNumber(item.minimum_stock)}</small></div><span class="pill red">SHORT</span></div>`).join("")}
        ${readyRefinery.slice(0,2).map((job) => `<div class="list-item"><div><strong>${escapeHtml(job.material_name)} refinery job</strong><small>${escapeHtml(job.refinery_location)} · collection ${formatDate(job.collection_deadline)}</small></div><span class="pill amber">COLLECT</span></div>`).join("")}
        ${!shortages.length && !readyRefinery.length ? `<div class="notice">No immediate logistics warnings.</div>` : ""}
      </div></section>
      <section class="card pad">${header("Threat picture", "Active intelligence still within its confirmation window.", `<button class="button small ghost" data-go="intel">Open intelligence</button>`)}<div class="list">${activeIntel.slice(0,4).map((report) => `<div class="list-item"><div><strong>${escapeHtml(report.title)}</strong><small>${escapeHtml(report.system_name)} · expires ${formatDate(report.expires_at)}</small></div>${pill(report.threat_level)}</div>`).join("") || `<div class="notice">No active reports.</div>`}</div></section>
      <section class="card pad">${header("Personal command queue", "Items needing your attention.", `<button class="button small ghost" data-go="notifications">Open notifications</button>`)}<div class="list">
        <div class="list-item"><div><strong>${unread.length} unread notifications</strong><small>Verification, refinery and operation updates.</small></div><span class="pill cyan">COMMS</span></div>
        <div class="list-item"><div><strong>${openOrders.filter((w) => w.claimed_by === profile.id).length} claimed jobs</strong><small>Work orders currently assigned to you.</small></div><span class="pill amber">TASKS</span></div>
      </div></section>
    </div>`;
  bindGoButtons();
}

function bindGoButtons() { $$('[data-go]').forEach((button) => button.addEventListener("click", () => window.dispatchEvent(new CustomEvent("free-navy:navigate", { detail: button.dataset.go })))); }

async function renderSearch(content, profile, context = {}) {
  const snapshot = await db.snapshot(); const q = (context.query ?? state.query ?? "").trim().toLowerCase(); state.query = q;
  const tableLabels = Object.fromEntries([...Object.entries(moduleDefs).map(([id,d]) => [d.table,pageMeta[id]?.[0] || id]), ["operations","Operations"], ["auctions","Auctions"], ["profiles","Members"], ["blueprints","Blueprints"]]);
  const results = [];
  if (q) for (const [table, rows] of Object.entries(snapshot)) for (const row of (rows || [])) {
    if (!isLiveRow(row)) continue; const text = JSON.stringify(row).toLowerCase(); if (!text.includes(q)) continue;
    const title = row.title || row.name || row.item_name || row.material_name || row.ship_name || row.display_name || row.feature || row.id;
    results.push({ table, title, summary: Object.entries(row).filter(([k,v]) => !["id","created_at","updated_at"].includes(k) && typeof v !== "object" && v !== "").slice(0,5).map(([k,v]) => `${titleCase(k)}: ${v}`).join(" · ") });
  }
  content.innerHTML = `${pageHero("Search the organisation network", "Find items, ships, members, coordinates, blueprints, jobs, operations and internal listings from one place.")}
    <form id="page-search-form" class="search-panel card pad"><input id="page-search-input" type="search" value="${escapeHtml(context.query ?? state.query)}" placeholder="Search Helix II, Stileron, Reclaimer, Pyro…"><button class="button primary">Search</button></form>
    ${q ? header(`${results.length} result${results.length === 1 ? "" : "s"}`, `Search results for “${q}”.`) : ""}
    <div class="search-results">${q ? (results.length ? results.slice(0,100).map((r) => `<article class="card pad search-result"><span class="pill cyan">${escapeHtml(tableLabels[r.table] || titleCase(r.table))}</span><h3>${escapeHtml(r.title)}</h3><p>${escapeHtml(r.summary)}</p></article>`).join("") : emptyState("Nothing found", "Try another item, location, member or ship name.")) : emptyState("Search is ready", "Enter any term from across the Free Navy command network.")}</div>`;
  $("#page-search-form").addEventListener("submit", (event) => { event.preventDefault(); window.dispatchEvent(new CustomEvent("free-navy:search", { detail: $("#page-search-input").value })); });
}

async function renderNotifications(content, profile) {
  const rows = (await db.list("notifications")).filter((n) => n.member_id === profile.id).sort((a,b) => new Date(b.created_at)-new Date(a.created_at));
  content.innerHTML = `${pageHero("Notifications", "Your operation, verification, refinery, marketplace and security updates.")}${header("Comms queue", `${rows.filter((r) => !r.read_at).length} unread message(s).`, rows.some((r) => !r.read_at) ? `<button id="mark-all-read" class="button">Mark all read</button>` : "")}
    <div class="list">${rows.length ? rows.map((n) => `<div class="list-item ${n.read_at ? "read" : "unread"}"><div><strong>${escapeHtml(n.title)}</strong><small>${escapeHtml(n.message)} · ${formatDate(n.created_at)}</small></div>${n.read_at ? `<span class="pill">READ</span>` : `<button class="button small" data-read="${n.id}">Mark read</button>`}</div>`).join("") : emptyState("No notifications", "Your comms queue is clear.")}</div>`;
  $$('[data-read]').forEach((button) => button.addEventListener("click", async () => { await db.rpc("mark_notification_read", { target_notification: button.dataset.read }); await renderNotifications(content, profile); window.dispatchEvent(new CustomEvent("free-navy:notifications-changed")); }));
  $("#mark-all-read")?.addEventListener("click", async () => { await db.rpc("mark_all_notifications_read"); await renderNotifications(content, profile); window.dispatchEvent(new CustomEvent("free-navy:notifications-changed")); });
}

async function renderWarehouse(content, profile) {
  await renderDirectoryPage(content, profile, "warehouse", () => renderWarehouse(content, profile));
  const [items, movements, loans] = await Promise.all([db.list("warehouse_items"), db.list("inventory_movements"), db.list("equipment_loans", { order: "requested_at", ascending: false }).catch(() => [])]);
  const manage = canManage(profile, "warehouse");
  content.insertAdjacentHTML("beforeend", `<section class="card pad page-section">
    ${header("Chain of custody", "Deposits, withdrawals, reservations, releases and transfers are recorded against a member and linked job.", manage ? `<div class="button-row"><button id="adjust-reservation" class="button">Reserve / release stock</button><button id="record-movement" class="button ghost">Record movement</button></div>` : "")}
    <div class="table-wrap"><table><thead><tr><th>Item</th><th>Movement</th><th>Quantity</th><th>From</th><th>To</th><th>Member</th><th>Linked record</th><th>Status</th><th>Date</th></tr></thead><tbody>${movements.slice(0,100).map((row)=>`<tr><td>${escapeHtml(row.item_name)}</td><td>${pill(row.movement_type)}</td><td>${formatNumber(row.quantity)} ${escapeHtml(row.unit||"")}</td><td>${escapeHtml(row.from_location||"—")}</td><td>${escapeHtml(row.to_location||"—")}</td><td>${escapeHtml(profileName(row.member_id))}</td><td>${escapeHtml(row.linked_record||"—")}</td><td>${pill(row.status)}</td><td>${formatDate(row.created_at)}</td></tr>`).join("")||`<tr><td colspan="9">${emptyState("No stock movements", "The chain-of-custody log is empty.")}</td></tr>`}</tbody></table></div>
  </section>
  <section class="card pad page-section">${header("Equipment checkout and returns","Members can request organisation equipment. Quartermasters approve, issue and record returns; high-value issues require a second authorised approval.",`<button id="request-equipment" class="button primary">Request equipment</button>`)}<div class="table-wrap"><table><thead><tr><th>Item</th><th>Member</th><th>Quantity</th><th>Status</th><th>Due</th><th>Evidence / notes</th><th>Actions</th></tr></thead><tbody>${loans.map(loan=>`<tr><td>${escapeHtml(loan.item_name)}</td><td>${escapeHtml(profileName(loan.member_id))}</td><td>${formatNumber(loan.quantity)} ${escapeHtml(loan.unit||"")}</td><td>${pill(loan.status)}</td><td>${formatDate(loan.due_at)}</td><td>${loan.evidence_url?`<a href="${escapeHtml(loan.evidence_url)}" target="_blank" rel="noreferrer">Evidence</a>`:""} ${escapeHtml(loan.notes||"")}</td><td><div class="table-actions">${manage&&loan.status==="requested"?`<button class="button small primary" data-loan-action="approved" data-loan="${loan.id}">Approve</button><button class="button small danger" data-loan-action="rejected" data-loan="${loan.id}">Reject</button>`:""}${manage&&loan.status==="approved"?`<button class="button small" data-loan-action="issued" data-loan="${loan.id}">Issue</button>`:""}${(manage||loan.member_id===profile.id)&&loan.status==="issued"?`<button class="button small" data-loan-action="returned" data-loan="${loan.id}">Return</button><button class="button small danger" data-loan-action="lost" data-loan="${loan.id}">Report lost</button>`:""}</div></td></tr>`).join("")||`<tr><td colspan="7">${emptyState("No equipment loans","Request equipment from the organisation warehouse.")}</td></tr>`}</tbody></table></div></section>`);
  $("#request-equipment", content)?.addEventListener("click", () => {
    const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">EQUIPMENT REQUEST</p><h2>Request organisation equipment</h2><form id="equipment-request-form" class="stack-form"><label>Warehouse item<select name="item">${items.map(item=>`<option value="${item.id}" data-name="${escapeHtml(item.name)}" data-unit="${escapeHtml(item.unit||"unit")}">${escapeHtml(item.name)} · ${formatNumber(Number(item.quantity||0)-Number(item.reserved_quantity||0))} available</option>`).join("")}</select></label><label>Quantity<input name="quantity" type="number" min="0.01" step="0.01" value="1" required></label><label>Needed until<input name="due_at" type="datetime-local"></label><label>Reason / operation<textarea name="notes" required></textarea></label><button class="button primary">Submit request</button></form>`);
    $("#equipment-request-form",modal.card).addEventListener("submit",async(event)=>{event.preventDefault();const form=event.currentTarget;const item=items.find(row=>row.id===form.item.value);try{await db.create("equipment_loans",{warehouse_item_id:item.id,item_name:item.name,quantity:Number(form.quantity.value),unit:item.unit||"unit",due_at:form.due_at.value||null,notes:form.notes.value,status:"requested"});modal.close();toast("Equipment request sent to the Quartermasters.","success");await renderWarehouse(content,profile);}catch(error){toast(error.message,"error",6000);}});
  });
  $$('[data-loan-action]',content).forEach(button=>button.addEventListener("click",async()=>{const status=button.dataset.loanAction;const notes=prompt(status==="returned"?"Condition on return:":"Notes:","")||"";try{const result=await db.rpc("manage_equipment_loan",{loan_id:button.dataset.loan,status,condition_in:status==="returned"?notes:"",notes});if(result?.pending_approval)toast(`High-value issue sent for second approval (${formatCredits(result.total_value)}).`,"warning",7000);else toast(`Equipment loan marked ${status}.`,"success");await renderWarehouse(content,profile);}catch(error){toast(error.message,"error",7000);}}));
  $("#adjust-reservation", content)?.addEventListener("click", () => {
    const modal = openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">ATOMIC STOCK CONTROL</p><h2>Reserve or release warehouse stock</h2><form id="reservation-form" class="stack-form"><label>Warehouse item<select name="item" required>${items.map((item)=>`<option value="${item.id}">${escapeHtml(item.name)} · ${formatNumber(Number(item.quantity||0)-Number(item.reserved_quantity||0))} ${escapeHtml(item.unit||"")} free</option>`).join("")}</select></label><label>Action<select name="action"><option value="reserve">Reserve</option><option value="release">Release</option></select></label><label>Quantity<input name="quantity" type="number" min="0.01" step="0.01" required></label><label>Linked operation, job or reason<input name="reference" required placeholder="OP-12 / crafting job / task"></label><button class="button primary">Apply reservation</button></form>`);
    $("#reservation-form",modal.card).addEventListener("submit",async(event)=>{event.preventDefault();const form=event.currentTarget;const quantity=Number(form.quantity.value)*(form.action.value==="release"?-1:1);try{await db.rpc("adjust_warehouse_reservation",{target_item:form.item.value,quantity_delta:quantity,linked_reference:form.reference.value});modal.close();toast("Warehouse reservation updated.","success");await renderWarehouse(content,profile);}catch(error){toast(error.message,"error",6000);}});
  });
  $("#record-movement", content)?.addEventListener("click", () => openSimpleCreate("inventory_movements","Record stock movement",[
    field("item_name","Item name","text",[],{required:true}),field("quantity","Quantity","number"),field("unit","Unit"),field("movement_type","Movement","select",["deposit","withdrawal","transfer","loaded","delivered","returned","lost"]),field("from_location","From"),field("to_location","To"),field("member_id","Responsible member","profile"),field("linked_record","Linked record"),field("status","Status","select",["pending","active","complete","lost"])
  ],profile,()=>renderWarehouse(content,profile)));
}

