async function renderCrafting(content, profile) {
  const [blueprints, warehouse, jobRows] = await Promise.all([db.blueprints(), db.list("warehouse_items"), db.list("production_jobs")]); state.blueprints = liveRows(blueprints); state.warehouse = warehouse; const jobs = liveRows(jobRows);
  const manage = canManage(profile,"crafting");
  content.innerHTML = `${pageHero("Crafting and blueprint command", "Blueprint ownership, material quality, shortages, production queues and warehouse reservations for the LIVE environment.")}
    ${header("Blueprint library", `${state.blueprints.length} blueprint records match Alpha ${LIVE_PATCH} LIVE.`, manage ? `<button id="add-blueprint" class="button primary">Add blueprint</button>` : "")}
    <div class="blueprint-grid">${state.blueprints.map((bp) => {
      const materials = bp.materials || []; const missing = materials.reduce((sum,m) => { const stock = warehouse.filter((w) => w.name.toLowerCase() === String(m.material_name).toLowerCase()).reduce((s,w) => s + Number(w.quantity||0)-Number(w.reserved_quantity||0),0); return sum + Math.max(0, Number(m.quantity)-stock); },0);
      return `<article class="card blueprint-card"><div class="blueprint-card-header"><div><h3>${escapeHtml(bp.name)}</h3><small class="muted">${escapeHtml(bp.category)} · ${escapeHtml(bp.source || "Unknown source")}</small></div>${pill(bp.status)}</div><div class="blueprint-meta"><span class="pill cyan">Q ${formatNumber(bp.quality_target)}</span><span class="pill ${missing ? "red" : "green"}">${missing ? `${formatNumber(missing)} short` : "Ready"}</span></div><div class="material-list">${materials.map((m) => { const stock = warehouse.filter((w) => w.name.toLowerCase() === String(m.material_name).toLowerCase()).reduce((s,w) => s + Number(w.quantity||0)-Number(w.reserved_quantity||0),0); return `<div class="material-row"><div><strong>${escapeHtml(m.material_name)}</strong><small>${formatNumber(stock)} available · minimum quality ${formatNumber(m.quality_min)}</small></div><span class="${stock >= m.quantity ? "enough" : "shortage"}">${formatNumber(m.quantity)} ${escapeHtml(m.unit)}</span></div>`; }).join("")}</div><p>${escapeHtml(bp.notes || "")}</p></article>`;
    }).join("") || emptyState("No blueprints", "Add the first LIVE blueprint record.")}</div>
    <section class="card pad page-section">${header("Production queue", "Active crafting jobs and assigned output locations.", manage ? `<button id="add-production-job" class="button">Add production job</button>` : "")}<div class="table-wrap"><table><thead><tr><th>Blueprint</th><th>Qty</th><th>Quality</th><th>Status</th><th>Assigned</th><th>Due</th><th>Output</th></tr></thead><tbody>${jobs.map((j) => `<tr><td>${escapeHtml(j.blueprint_name)}</td><td>${formatNumber(j.quantity)}</td><td>${formatNumber(j.quality_target)}</td><td>${pill(j.status)}</td><td>${escapeHtml(profileName(j.assigned_to))}</td><td>${formatDate(j.due_at)}</td><td>${escapeHtml(j.output_location)}</td></tr>`).join("") || `<tr><td colspan="7">${emptyState("No production jobs", "The queue is clear.")}</td></tr>`}</tbody></table></div></section>`;
  $("#add-blueprint")?.addEventListener("click", () => {
    const modal = openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">NEW BLUEPRINT</p><h2>Add blueprint</h2><form id="blueprint-form"><div class="form-grid"><label class="field">Name<input name="name" required></label><label class="field">Category<input name="category"></label><label class="field">Status<select name="status"><option>owned</option><option>research</option><option>missing</option></select></label><label class="field">Quality target<input name="quality_target" type="number" value="500"></label><label class="field">Source<input name="source"></label><label class="field checkbox-field"><input name="active" type="checkbox" checked> Active production blueprint</label><label class="field full-span">Materials, one per line: name | quantity | unit | minimum quality<textarea name="materials" placeholder="Stileron | 240 | units | 550"></textarea></label><label class="field full-span">Notes<textarea name="notes"></textarea></label></div><div class="form-actions"><button class="button primary">Add blueprint</button></div></form>`,true);
    $("#blueprint-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;await db.createBlueprint({name:f.name.value,category:f.category.value,status:f.status.value,quality_target:Number(f.quality_target.value),source:f.source.value,active:f.active.checked,notes:f.notes.value,game_version:LIVE_PATCH},parseMaterialLines(f.materials.value));modal.close();toast("Blueprint added.","success");await renderCrafting(content,profile);});
  });
  $("#add-production-job")?.addEventListener("click", () => openSimpleCreate("production_jobs", "Add production job", [field("blueprint_name","Blueprint"),field("quantity","Quantity","number"),field("quality_target","Quality target","number"),field("status","Status","select",["queued","materials gathering","crafting","complete"]),field("assigned_to","Assigned","profile"),field("output_location","Output location"),field("due_at","Due","datetime-local"),field("notes","Notes","textarea")], profile, () => renderCrafting(content,profile), { game_version: LIVE_PATCH }));
}

async function openSimpleCreate(table,title,fields,profile,refresh,defaults = {}) {
  await loadProfiles(); const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">NEW RECORD</p><h2>${escapeHtml(title)}</h2><form id="simple-form"><div class="form-grid">${fields.map((f)=>formControl(f)).join("")}</div><div class="form-actions"><button class="button primary">Create</button></div></form>`,true);
  $("#simple-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const payload={...defaults,...Object.fromEntries(fields.map((f)=>[f.name,normaliseFormValue(f,e.currentTarget)]))};await db.create(table,payload);modal.close();toast("Record created.","success");await refresh();});
}

async function renderTrade(content, profile) {
  const [commoditiesResult, terminalsResult] = await Promise.all([db.uex("commodities"), db.uex("terminals")]);
  const commodities = commoditiesResult.data || []; const terminals = terminalsResult.data || [];
  content.innerHTML = `${pageHero("UEX trade planner", `Routes and calculations are filtered to Alpha ${LIVE_PATCH} LIVE. UEX is community-maintained, so freshness and member verification still matter.`)}
    <section class="card pad">${header("Route search", "Choose at least one origin or commodity. Results are LIVE-gated by the server proxy.")}
      <form id="route-form" class="trade-controls"><label class="field">Commodity<select name="id_commodity"><option value="">Any commodity</option>${commodities.map((c)=>`<option value="${c.id}">${escapeHtml(c.name)}</option>`).join("")}</select></label><label class="field">Origin<select name="id_terminal_origin"><option value="">Any origin</option>${terminals.map((t)=>`<option value="${t.id}">${escapeHtml(t.name)}</option>`).join("")}</select></label><label class="field">Destination<select name="id_terminal_destination"><option value="">Any destination</option>${terminals.map((t)=>`<option value="${t.id}">${escapeHtml(t.name)}</option>`).join("")}</select></label><label class="field">Investment limit<input name="investment" type="number" min="0" placeholder="aUEC"></label><button class="button primary">Find routes</button></form>
      <div id="route-results" class="list page-section"></div>
    </section>
    <section class="card pad page-section">${header("Manual cargo calculator", "Useful when a member has just confirmed a price in-game.")}
      <form id="calculator-form" class="trade-controls"><label class="field">Buy price / SCU<input name="buy" type="number" step="0.01" required></label><label class="field">Sell price / SCU<input name="sell" type="number" step="0.01" required></label><label class="field">Cargo SCU<input name="scu" type="number" step="0.01" required></label><label class="field">Other costs<input name="costs" type="number" value="0"></label><button class="button">Calculate</button></form><div id="calculator-result"></div>
    </section>`;
  const form=$("#route-form"); form.addEventListener("submit",async(e)=>{e.preventDefault();const button=e.submitter;setLoading(button,true,"Searching…");try{const params=Object.fromEntries(new FormData(form).entries());if(!params.id_commodity&&!params.id_terminal_origin) return toast("Choose a commodity or origin.","warning");const result=await db.uex("commodities_routes",params);const routes=(result.data||[]).filter((r)=>!r.game_version_origin||r.game_version_origin===LIVE_PATCH).filter((r)=>!r.game_version_destination||r.game_version_destination===LIVE_PATCH);$("#route-results").innerHTML=routes.length?routes.slice(0,50).map((r)=>`<div class="route-card card"><div><div class="route-path"><strong>${escapeHtml(r.origin_terminal_name||"Origin")}</strong><span class="route-arrow">→</span><strong>${escapeHtml(r.destination_terminal_name||"Destination")}</strong></div><small class="muted">${escapeHtml(r.commodity_name||"Commodity")} · ${formatNumber(r.distance,1)} GM · UEX score ${formatNumber(r.score)}</small></div><div class="route-numbers"><div><small>BUY</small>${formatCredits(r.price_origin)}</div><div><small>SELL</small>${formatCredits(r.price_destination)}</div><div><small>MAX PROFIT</small><strong class="positive">${formatCredits(r.profit)}</strong></div></div></div>`).join(""):emptyState("No LIVE routes returned","Try another origin or commodity.");}catch(error){toast(error.message,"error");}finally{setLoading(button,false);}});
  $("#calculator-form").addEventListener("submit",(e)=>{e.preventDefault();const f=e.currentTarget,buy=Number(f.buy.value),sell=Number(f.sell.value),scu=Number(f.scu.value),costs=Number(f.costs.value||0),investment=buy*scu,profit=(sell-buy)*scu-costs,roi=investment?profit/investment*100:0;$("#calculator-result").innerHTML=`<div class="grid cols-3 page-section">${metric("Investment",formatCredits(investment),`${formatNumber(scu)} SCU`,"BUY")}${metric("Net profit",formatCredits(profit),`${formatNumber(roi,1)}% ROI`,"PROFIT")}${metric("Break-even sell",formatCredits(buy+(costs/scu||0)),"Per SCU","RISK")}</div>`;});
}

async function renderKnowledge(content, profile) {
  await renderDirectoryPage(content, profile, "knowledge", () => renderKnowledge(content, profile));
  const hero = $(".page-hero", content);
  if (!hero) return;
  hero.insertAdjacentHTML("afterend", `<section class="card pad live-lookup-card">
    ${header("LIVE UEX location lookup", `External results are accepted only when they match Alpha ${LIVE_PATCH} LIVE. Free Navy verification remains separate.`, `<span class="pill cyan">UEX + ORG KNOWLEDGE</span>`)}
    <form id="uex-location-form" class="trade-controls">
      <label class="field">Lookup type<select name="lookup_type"><option value="commodity">Commodity name</option><option value="item">UEX item ID</option></select></label>
      <label class="field lookup-query-field">Search<input name="query" placeholder="Gold" required></label>
      <button class="button primary">Search LIVE sources</button>
    </form>
    <div class="notice compact"><strong>Why item ID?</strong> UEX item-price requests require an item ID or terminal ID. Commodity prices can be searched directly by name.</div>
    <div id="uex-location-results" class="list page-section"></div>
  </section>`);
  const form = $("#uex-location-form", content);
  const type = form.elements.lookup_type;
  const query = form.elements.query;
  const updatePlaceholder = () => { query.placeholder = type.value === "commodity" ? "Gold, Helium, Medical Supplies…" : "UEX item ID, for example 9001"; };
  type.addEventListener("change", updatePlaceholder); updatePlaceholder();
  form.addEventListener("submit", async (event) => {
    event.preventDefault(); const button = event.submitter; const value = query.value.trim();
    if (!value) return;
    if (type.value === "item" && !/^\d+$/.test(value)) return toast("UEX item lookup requires a numeric item ID.", "warning", 5000);
    setLoading(button, true, "Checking…");
    try {
      const resource = type.value === "commodity" ? "commodities_prices" : "items_prices";
      const params = type.value === "commodity" ? { commodity_name: value } : { id_item: value };
      const result = await db.uex(resource, params);
      const rows = (result.data || []).filter((row) => !row.game_version || String(row.game_version) === String(LIVE_PATCH));
      const rejected = Number(result.rejected_non_live_rows || 0);
      $("#uex-location-results", content).innerHTML = `${rejected ? `<div class="notice warning">${rejected} non-LIVE result(s) were blocked by the server gate.</div>` : ""}${rows.length ? rows.slice(0,80).map((row) => {
        const place = [row.terminal_name, row.space_station_name, row.city_name, row.outpost_name, row.planet_name, row.star_system_name].filter(Boolean).filter((item,index,array)=>array.indexOf(item)===index).join(" · ");
        const modified = row.date_modified ? new Date(Number(row.date_modified) * 1000).toISOString() : null;
        return `<div class="list-item uex-price-row"><div><strong>${escapeHtml(row.commodity_name || row.item_name || value)}</strong><small>${escapeHtml(place || "Location not supplied")} · Updated ${formatDate(modified)}</small></div><div class="price-badges">${Number(row.price_buy || 0) ? `<span class="pill green">BUY ${formatCredits(row.price_buy)}</span>` : ""}${Number(row.price_sell || 0) ? `<span class="pill amber">SELL ${formatCredits(row.price_sell)}</span>` : ""}<span class="pill cyan">${escapeHtml(row.game_version || LIVE_PATCH)} LIVE</span></div></div>`;
      }).join("") : emptyState("No matching LIVE locations", "Try the exact commodity name or verify the UEX item ID.")}`;
    } catch (error) { toast(error.message, "error", 6000); }
    finally { setLoading(button, false); }
  });
}

async function renderAuctions(content, profile) {
  await loadProfiles(); const auctions=await db.list("auctions",{order:"ends_at",ascending:true}); const manage=canManage(profile,"auctions");
  content.innerHTML=`${pageHero("Organisation auction house","Bid with member points. Active bids reserve points until outbid or the auction is resolved.")}${header("Organisation auctions",`${auctions.filter(a=>a.status==="open").length} accepting bids.`,manage?`<button id="add-auction" class="button primary">Create auction</button>`:"")}
    <div class="auction-grid">${auctions.map((a)=>`<article class="card auction-card"><div class="auction-image item-fallback">FREE NAVY LOT</div><div class="card-body"><div class="card-topline"><div><h3>${escapeHtml(a.title)}</h3><p>${escapeHtml(a.description)}</p></div>${pill(a.status)}</div><div class="price-line"><div><small class="muted">Current bid</small><strong>${formatNumber(a.current_bid||a.starting_bid)} pts</strong><small class="muted">${a.current_winner_id?`Leader: ${escapeHtml(profileName(a.current_winner_id))}`:"No bids"}</small></div><div><small class="muted">Ends</small><div>${formatDate(a.ends_at)}</div></div></div>${a.status==="open"&&new Date(a.ends_at)>new Date()?`<form class="bid-form" data-auction="${a.id}"><input name="bid" type="number" min="${Number(a.current_bid||a.starting_bid)+1}" placeholder="Bid points" required><button class="button primary">Bid</button></form>`:""}${manage&&a.status==="open"?`<div class="button-row auction-admin-actions"><button class="button small" data-resolve-auction="${a.id}" data-resolution="completed">Complete</button><button class="button small danger" data-resolve-auction="${a.id}" data-resolution="cancelled">Cancel & refund</button></div>`:""}</div></article>`).join("")||emptyState("No auctions","The auction vault is empty.")}</div>`;
  $$('.bid-form').forEach((form)=>form.addEventListener("submit",async(e)=>{e.preventDefault();const button=e.submitter;setLoading(button,true,"Bidding…");try{await db.rpc("place_auction_bid",{target_auction:form.dataset.auction,bid_amount:Number(form.bid.value)});toast("Bid placed and points reserved.","success");await renderAuctions(content,profile);}catch(error){toast(error.message,"error");}finally{setLoading(button,false);}}));
  $$('[data-resolve-auction]').forEach((button)=>button.addEventListener("click",async()=>{const resolution=button.dataset.resolution;const warning=resolution==="cancelled"?"Cancel this auction and refund the leading bid?":"Complete this auction and keep the winning bid charged?";if(!confirm(warning))return;try{await db.rpc("resolve_auction",{target_auction:button.dataset.resolveAuction,resolution});toast(resolution==="cancelled"?"Auction cancelled and leading bid refunded.":"Auction completed.","success");await renderAuctions(content,profile);}catch(error){toast(error.message,"error",6000);}}));
  $("#add-auction")?.addEventListener("click",()=>openSimpleCreate("auctions","Create auction",[field("title","Title"),field("description","Description","textarea"),field("starting_bid","Starting points","number"),field("ends_at","Ends","datetime-local"),field("status","Status","select",["open"])],profile,()=>renderAuctions(content,profile),{current_bid:0,created_by:profile.id}));
}

async function renderTreasury(content, profile) {
  const [profiles, donations, ledger]=await Promise.all([loadProfiles(),db.list("donations"),db.list("points_ledger")]); const manage=canManage(profile,"treasury");
  const total=donations.filter(d=>d.donation_type==="aUEC").reduce((s,d)=>s+Number(d.amount||0),0);
  content.innerHTML=`${pageHero("Treasury and points ledger","Every point change is a transaction, not an editable mystery number.")}<div class="grid cols-3">${metric("Recorded aUEC",formatCredits(total),`${donations.length} contributions`,"BANK")}${metric("Points in circulation",formatNumber(profiles.reduce((s,p)=>s+Number(p.points_balance||0),0)),`${profiles.length} member accounts`,"PTS")}${metric("Ledger entries",ledger.length,"Credits, debits and adjustments","LOG")}</div>
    <section class="card pad page-section">${header("Member balances","Current spendable points.",manage?`<button id="award-points" class="button primary">Award / adjust points</button>`:"")}<div class="table-wrap"><table><thead><tr><th>Member</th><th>Role</th><th>Points</th><th>Status</th></tr></thead><tbody>${profiles.map(p=>`<tr><td>${escapeHtml(p.display_name)}</td><td>${escapeHtml(rankLabel(p.rank || "enlisted"))}</td><td>${formatNumber(p.points_balance)}</td><td>${pill(p.status)}</td></tr>`).join("")}</tbody></table></div></section>
    <section class="card pad page-section">${header("Points ledger","Permanent audit trail of organisation point movements.")}<div class="table-wrap"><table><thead><tr><th>Member</th><th>Amount</th><th>Reason</th><th>Linked record</th><th>Authorised by</th><th>Date</th></tr></thead><tbody>${ledger.map(l=>`<tr><td>${escapeHtml(profileName(l.member_id))}</td><td class="${Number(l.amount)>=0?"positive":"negative"}">${Number(l.amount)>=0?"+":""}${formatNumber(l.amount)}</td><td>${escapeHtml(l.reason)}</td><td>${escapeHtml(l.linked_record||"—")}</td><td>${escapeHtml(profileName(l.created_by))}</td><td>${formatDate(l.created_at)}</td></tr>`).join("")}</tbody></table></div></section>`;
  $("#award-points")?.addEventListener("click",()=>{const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">POINTS LEDGER</p><h2>Award or adjust points</h2><form id="points-form" class="stack-form"><label>Member<select name="member">${profiles.map(p=>`<option value="${p.id}">${escapeHtml(p.display_name)}</option>`).join("")}</select></label><label>Amount<input name="amount" type="number" required><small class="muted">Use a negative value to deduct points.</small></label><label>Reason<input name="reason" required></label><label>Linked record<input name="linked"></label><button class="button primary">Post transaction</button></form>`);$("#points-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;await db.rpc("award_member_points",{target_member:f.member.value,point_amount:Number(f.amount.value),point_reason:f.reason.value,linked_record:f.linked.value});modal.close();toast("Points transaction posted.","success");await renderTreasury(content,profile);});});
}

async function renderOperations(content, profile) {
  await loadProfiles();
  const [operations,attendance,templates,updates]=await Promise.all([
    db.list("operations",{order:"start_at",ascending:true}),db.list("operation_attendance"),db.list("operation_templates",{order:"name",ascending:true}).catch(()=>[]),db.list("operation_updates",{order:"created_at",ascending:false}).catch(()=>[])
  ]);
  const manage=canManage(profile,"operations"), canTreasury=Boolean(profile.capabilities?.manage_treasury);
  content.innerHTML=`${pageHero("Operations centre","Reusable templates, live command rooms, attendance, contribution scoring and after-action records for LIVE activities.")}${header("Scheduled and completed operations",`${liveRows(operations).length} operation records.`,manage?`<div class="button-row"><button id="add-operation" class="button primary">Create operation</button><button id="add-operation-template" class="button">Add template</button></div>`:"")}
    <div class="operation-grid">${liveRows(operations).map(op=>{const attendees=attendance.filter(a=>a.operation_id===op.id);const mine=attendees.find(a=>a.member_id===profile.id);const opUpdates=updates.filter(u=>u.operation_id===op.id).slice(0,8);return `<article class="card operation-card ${op.emergency_status==='emergency'?'emergency-card':''}"><div class="card-body"><div class="card-topline"><div><h3>${escapeHtml(op.title)}</h3><small class="muted">${formatDate(op.start_at)} · ${escapeHtml(op.location||"Location TBC")}</small></div><div class="button-row">${pill(op.status)}${op.emergency_status!=='normal'?pill(op.emergency_status):''}</div></div><p>${escapeHtml(op.briefing||"")}</p><div class="blueprint-meta"><span class="pill cyan">${escapeHtml(op.operation_type||"Operation")}</span><span class="pill">Commander: ${escapeHtml(profileName(op.commander_id))}</span><span class="pill">${attendees.filter(a=>a.status==="accepted").length} crew</span><span class="pill amber">${formatNumber(op.reward_points)} pts</span></div><div class="operation-status-grid"><div><small>Phase</small><strong>${escapeHtml(titleCase(op.current_phase||"briefing"))}</strong></div><div><small>Objective</small><strong>${escapeHtml(op.objective_status||"Not set")}</strong></div><div><small>Voice channel</small><strong>${escapeHtml(op.voice_channel||"Not set")}</strong></div></div><small class="muted">Required: ${escapeHtml(op.required_roles||"TBC")}</small>${!["completed","cancelled"].includes(op.status)?`<div class="operation-actions"><button class="button small ${mine?.status==="accepted"?"primary":""}" data-rsvp="${op.id}" data-status="accepted">Attend</button><button class="button small ghost" data-rsvp="${op.id}" data-status="tentative">Tentative</button><button class="button small ghost" data-rsvp="${op.id}" data-status="declined">Decline</button></div>`:""}<div class="command-room"><h4>Command-room feed</h4>${opUpdates.map(update=>`<div class="command-update ${escapeHtml(update.update_type)}"><span>${escapeHtml(titleCase(update.update_type))}</span><p>${escapeHtml(update.message)}</p><small>${escapeHtml(profileName(update.created_by))} · ${formatDate(update.created_at)}</small></div>`).join("")||'<small class="muted">No live updates posted.</small>'}${manage?`<button class="button small" data-post-operation-update="${op.id}">Post update</button>`:""}</div><div class="operation-roster"><h4>Crew and contribution records</h4>${attendees.map(a=>`<div class="list-item"><div><strong>${escapeHtml(profileName(a.member_id))}</strong><small>${escapeHtml(a.crew_role||"Role not assigned")} · ${escapeHtml(titleCase(a.status||"pending"))}</small><small>${formatNumber(a.minutes_attended)} min · ${formatNumber(a.materials_contributed)} materials · ${formatNumber(a.cargo_transported)} cargo · ${formatNumber(a.calculated_points)} calculated pts${a.approved_points!=null?` · ${formatNumber(a.approved_points)} approved`:''}</small></div><div class="button-row">${manage?`<button class="button small ghost" data-score-attendance="${a.id}" data-operation="${op.id}" data-member="${a.member_id}">Score</button>`:""}${canTreasury&&a.approved_points==null?`<button class="button small primary" data-approve-operation-points="${a.id}">Approve points</button>`:""}</div></div>`).join("")||'<small class="muted">No crew responses yet.</small>'}</div></div></article>`;}).join("")||emptyState("No operations","Create the first operation from a reusable template.")}</div>`;
  $$('[data-rsvp]').forEach(b=>b.addEventListener("click",async()=>{const role=prompt("Crew role:","")||"";try{await db.rpc("rsvp_operation",{target_operation:b.dataset.rsvp,response_status:b.dataset.status,crew_role:role});toast("Operation response saved.","success");await renderOperations(content,profile);}catch(error){toast(error.message,"error",6000);}}));
  const operationForm=()=>{const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">NEW OPERATION</p><h2>Create operation</h2><form id="operation-form" class="stack-form"><label>Template<select name="template"><option value="">Blank operation</option>${templates.filter(t=>t.enabled!==false).map(t=>`<option value="${t.id}">${escapeHtml(t.name)}</option>`).join("")}</select></label><label>Title<input name="title" required></label><div class="grid cols-2"><label>Type<input name="operation_type"></label><label>Location<input name="location"></label></div><div class="grid cols-2"><label>Starts<input name="start_at" type="datetime-local"></label><label>Ends<input name="end_at" type="datetime-local"></label></div><label>Required roles<input name="required_roles"></label><label>Voice channel <span class="muted">(text reference only)</span><input name="voice_channel"></label><label>Briefing<textarea name="briefing" rows="6"></textarea></label><label>Reward points<input name="reward_points" type="number" value="0"></label><button class="button primary">Create operation</button></form>`,true);const form=$("#operation-form",modal.card);form.template.addEventListener("change",()=>{const t=templates.find(x=>x.id===form.template.value);if(!t)return;form.operation_type.value=t.operation_type||"";form.location.value=t.default_location||"";form.required_roles.value=t.required_roles||"";form.briefing.value=t.briefing_template||"";form.reward_points.value=t.default_reward_points||0;});form.addEventListener("submit",async(e)=>{e.preventDefault();try{await db.create("operations",{template_id:form.template.value||null,title:form.title.value,operation_type:form.operation_type.value,location:form.location.value,start_at:form.start_at.value||null,end_at:form.end_at.value||null,required_roles:form.required_roles.value,voice_channel:form.voice_channel.value,briefing:form.briefing.value,reward_points:Number(form.reward_points.value),commander_id:profile.id,status:"scheduled",current_phase:"briefing",emergency_status:"normal",game_version:LIVE_PATCH});modal.close();toast("Operation created.","success");await renderOperations(content,profile);}catch(error){toast(error.message,"error",6000);}});};
  $("#add-operation")?.addEventListener("click",operationForm);
  $("#add-operation-template")?.addEventListener("click",()=>openSimpleCreate("operation_templates","Add operation template",[field("name","Template name","text",[],{required:true}),field("operation_type","Operation type","text",[],{required:true}),field("default_location","Default location"),field("required_roles","Required roles"),field("briefing_template","Briefing template","textarea"),field("default_reward_points","Default points","number"),field("enabled","Enabled","checkbox")],profile,()=>renderOperations(content,profile),{created_by:profile.id,checklist:[]}));
  $$('[data-post-operation-update]').forEach(button=>button.addEventListener("click",()=>{const op=operations.find(x=>x.id===button.dataset.postOperationUpdate);const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">COMMAND ROOM</p><h2>${escapeHtml(op.title)}</h2><form id="operation-update-form" class="stack-form"><label>Update type<select name="update_type">${["status","objective","coordinate","warning","loss","announcement"].map(v=>`<option value="${v}">${titleCase(v)}</option>`).join("")}</select></label><label>Message<textarea name="message" rows="5" required></textarea></label><div class="grid cols-3"><label>Current phase<input name="current_phase" value="${escapeHtml(op.current_phase||'')}"></label><label>Emergency status<select name="emergency_status">${["normal","attention","emergency"].map(v=>`<option value="${v}" ${op.emergency_status===v?'selected':''}>${titleCase(v)}</option>`).join("")}</select></label><label>Objective status<input name="objective_status" value="${escapeHtml(op.objective_status||'')}"></label></div><button class="button primary">Post update</button></form>`);$("#operation-update-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;try{await db.rpc("post_operation_update",{operation_id:op.id,update_type:f.update_type.value,message:f.message.value,current_phase:f.current_phase.value,emergency_status:f.emergency_status.value,objective_status:f.objective_status.value});modal.close();toast("Command-room update posted.","success");await renderOperations(content,profile);}catch(error){toast(error.message,"error",6000);}});}));
  $$('[data-score-attendance]').forEach(button=>button.addEventListener("click",()=>{const record=attendance.find(a=>a.id===button.dataset.scoreAttendance);const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">CONTRIBUTION SCORE</p><h2>${escapeHtml(profileName(record.member_id))}</h2><form id="contribution-form" class="stack-form"><div class="grid cols-2"><label>Minutes attended<input name="minutes" type="number" value="${record.minutes_attended||0}"></label><label>Materials contributed<input name="materials" type="number" value="${record.materials_contributed||0}"></label><label>Cargo transported<input name="cargo" type="number" value="${record.cargo_transported||0}"></label><label>Rescue actions<input name="rescues" type="number" value="${record.rescue_actions||0}"></label><label>Objectives completed<input name="objectives" type="number" value="${record.objectives_completed||0}"></label><label>Calculated points<input name="points" type="number" value="${record.calculated_points||0}"></label></div><label>Ship supplied<input name="ship" value="${escapeHtml(record.ship_supplied||'')}"></label><label>Officer commendation<textarea name="commendation">${escapeHtml(record.officer_commendation||'')}</textarea></label><button class="button primary">Save contribution</button></form>`);$("#contribution-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;try{await db.rpc("record_operation_contribution",{operation_id:record.operation_id,member_id:record.member_id,minutes_attended:Number(f.minutes.value),materials_contributed:Number(f.materials.value),cargo_transported:Number(f.cargo.value),ship_supplied:f.ship.value,rescue_actions:Number(f.rescues.value),objectives_completed:Number(f.objectives.value),officer_commendation:f.commendation.value,calculated_points:Number(f.points.value)});modal.close();toast("Contribution score saved for Treasurer approval.","success");await renderOperations(content,profile);}catch(error){toast(error.message,"error",6000);}});}));
  $$('[data-approve-operation-points]').forEach(button=>button.addEventListener("click",async()=>{const record=attendance.find(a=>a.id===button.dataset.approveOperationPoints);const amount=Number(prompt("Approve operation points:",String(record.calculated_points||0)));if(!Number.isFinite(amount))return;try{const result=await db.rpc("approve_operation_points",{attendance_id:record.id,points:amount});toast(result?.pending_approval?"High-value points request sent for a second Treasurer or executive approval.":"Operation points approved and posted.",result?.pending_approval?"warning":"success",6500);await renderOperations(content,profile);}catch(error){toast(error.message,"error",6000);}}));
}

async function renderCatalog(content, profile) {
  const [rows, locations, flags] = await Promise.all([
    db.list("game_catalog", { order: "name", ascending: true, limit: 5000 }),
    db.list("catalog_locations", { order: "location_name", ascending: true, limit: 5000 }),
    db.list("data_flags", { order: "created_at" }).catch(() => [])
  ]);
  const types=[...new Set(rows.map(r=>r.entity_type).filter(Boolean))].sort();
  content.innerHTML=`${pageHero("LIVE game data library","Automatically published ships, vehicles, gear, components, commodities, blueprints and locations. Test-server records are rejected before publication.")}
    ${header("Imported catalogue",`${rows.length} LIVE records from configured sources.`,`<div class="button-row"><button id="submit-location" class="button ghost">Submit new location</button>${profile.capabilities?.edit_game_data?`<button id="open-sync" class="button primary">Manage imports</button>`:""}</div>`)}
    <div class="toolbar"><input id="catalog-filter" type="search" placeholder="Search ships, gear, minerals, manufacturers…"><select id="catalog-type"><option value="">All data types</option>${types.map(t=>`<option value="${escapeHtml(t)}">${escapeHtml(titleCase(t))}</option>`).join("")}</select></div>
    <div class="table-wrap"><table><thead><tr><th>Name</th><th>Type</th><th>Category</th><th>Manufacturer</th><th>Source</th><th>Locations</th><th>Status</th><th>Actions</th></tr></thead><tbody id="catalog-rows"></tbody></table></div>`;
  const render=()=>{const q=$("#catalog-filter").value.toLowerCase(),type=$("#catalog-type").value;const filtered=rows.filter(r=>(!type||r.entity_type===type)&&(!q||JSON.stringify(r).toLowerCase().includes(q)));$("#catalog-rows").innerHTML=filtered.length?filtered.slice(0,1000).map(r=>{const activeFlags=flags.filter(f=>f.target_table==="game_catalog"&&String(f.target_id)===String(r.id)&&["open","reviewing"].includes(f.status));const locs=locations.filter(l=>l.catalog_id===r.id);return `<tr><td><strong>${escapeHtml(r.name)}</strong><small class="table-subtext">${escapeHtml(r.description||"")}</small></td><td>${pill(r.entity_type)}</td><td>${escapeHtml(r.category||"—")}</td><td>${escapeHtml(r.manufacturer||"—")}</td><td>${escapeHtml(r.source_name)}</td><td>${locs.length?`${locs.length} known`:`<span class="muted">None imported</span>`}</td><td>${activeFlags.length?`<span class="pill red">FLAGGED ${activeFlags.length}</span>`:pill(r.confidence||r.status)}</td><td><div class="table-actions"><button class="button small ghost" data-catalog-detail="${r.id}">View</button><button class="button small ghost" data-catalog-flag="${r.id}">Flag</button>${profile.capabilities?.edit_game_data?`<button class="button small" data-catalog-edit="${r.id}">Edit</button>`:""}</div></td></tr>`;}).join(""):`<tr><td colspan="8">${emptyState("No matching records","Try another search or run the LIVE data importer.")}</td></tr>`;
    $$('[data-catalog-detail]').forEach(b=>b.addEventListener("click",()=>{const r=rows.find(x=>x.id===b.dataset.catalogDetail);const locs=locations.filter(l=>l.catalog_id===r.id);const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">${escapeHtml(titleCase(r.entity_type))}</p><h2>${escapeHtml(r.name)}</h2><div class="blueprint-meta"><span class="pill cyan">${escapeHtml(r.source_name)}</span><span class="pill green">LIVE ${escapeHtml(r.game_version)}</span>${pill(r.status)}${r.officer_locked?'<span class="pill amber">OFFICER LOCKED</span>':''}</div><p>${escapeHtml(r.description||"No description supplied by source.")}</p><h3>Known locations</h3><div class="list">${locs.map(l=>`<div class="list-item"><div><strong>${escapeHtml(l.location_name)}</strong><small>${escapeHtml([l.system_name,l.body_name,l.terminal_name].filter(Boolean).join(" · "))}</small>${l.officer_locked?'<small class="amber-text">Free Navy correction locked</small>':''}</div><div class="button-row"><span>${l.purchase_price_auec?formatCredits(l.purchase_price_auec):""}</span>${profile.capabilities?.edit_game_data?`<button class="button small ghost" data-edit-catalog-location="${l.id}">Edit location</button>`:""}</div></div>`).join("")||emptyState("No imported locations","Members can submit a new location through Where to Buy / Find.")}</div>`,true);$$('[data-edit-catalog-location]',modal.card).forEach(button=>button.addEventListener("click",()=>{const l=locations.find(item=>item.id===button.dataset.editCatalogLocation);const editor=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">OFFICER LOCATION CORRECTION</p><h2>${escapeHtml(l.entity_name)}</h2><form id="catalog-location-edit-form" class="stack-form"><div class="grid cols-2"><label>System<input name="system_name" value="${escapeHtml(l.system_name||"")}"></label><label>Planet / moon<input name="body_name" value="${escapeHtml(l.body_name||"")}"></label></div><label>Location<input name="location_name" value="${escapeHtml(l.location_name||"")}" required></label><label>Terminal / shop<input name="terminal_name" value="${escapeHtml(l.terminal_name||"")}"></label><div class="grid cols-2"><label>Purchase price<input name="purchase_price" type="number" min="0" value="${Number(l.purchase_price_auec||0)}"></label><label>Rental price<input name="rental_price" type="number" min="0" value="${Number(l.rental_price_auec||0)}"></label></div><label>Reason for correction<textarea name="reason" rows="3" required></textarea></label><button class="button primary">Save and lock correction</button>${l.officer_locked?'<button id="release-location-override" type="button" class="button ghost">Return to source control</button>':''}</form>`);$("#catalog-location-edit-form",editor.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;await db.update("catalog_locations",l.id,{system_name:f.system_name.value,body_name:f.body_name.value,location_name:f.location_name.value,terminal_name:f.terminal_name.value,purchase_price_auec:Number(f.purchase_price.value),rental_price_auec:Number(f.rental_price.value),confidence:"corrected",change_reason:f.reason.value});editor.close();modal.close();toast("Location correction locked against source overwrite.","success");await renderCatalog(content,profile);});$("#release-location-override",editor.card)?.addEventListener("click",async()=>{if(!confirm("Return this location to external source control on the next import?"))return;await db.rpc("release_data_override",{table:"catalog_locations",id:l.id});editor.close();modal.close();toast("Location returned to source control.","success");await renderCatalog(content,profile);});}));}));
    $$('[data-catalog-flag]').forEach(b=>b.addEventListener("click",()=>{const r=rows.find(x=>x.id===b.dataset.catalogFlag);openAccuracyFlag("game_catalog",r.id,r.name,()=>renderCatalog(content,profile));}));
    $$('[data-catalog-edit]').forEach(b=>b.addEventListener("click",()=>{const r=rows.find(x=>x.id===b.dataset.catalogEdit);const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">OFFICER CORRECTION</p><h2>Edit imported record</h2><form id="catalog-edit-form" class="stack-form"><label>Name<input name="name" value="${escapeHtml(r.name)}" required></label><label>Category<input name="category" value="${escapeHtml(r.category||"")}"></label><label>Manufacturer<input name="manufacturer" value="${escapeHtml(r.manufacturer||"")}"></label><label>Description<textarea name="description" rows="5">${escapeHtml(r.description||"")}</textarea></label><label>Status<select name="status"><option ${r.status==="active"?"selected":""}>active</option><option ${r.status==="flagged"?"selected":""}>flagged</option><option ${r.status==="stale"?"selected":""}>stale</option><option ${r.status==="removed"?"selected":""}>removed</option></select></label><label>Confidence<select name="confidence"><option ${r.confidence==="source"?"selected":""}>source</option><option ${r.confidence==="confirmed"?"selected":""}>confirmed</option><option ${r.confidence==="corrected"?"selected":""}>corrected</option><option ${r.confidence==="flagged"?"selected":""}>flagged</option><option ${r.confidence==="stale"?"selected":""}>stale</option></select></label><label>Reason for correction<textarea name="reason" rows="3" required></textarea></label><button class="button primary">Save and lock correction</button>${r.officer_locked?'<button id="release-catalog-override" type="button" class="button ghost">Return to source control</button>':''}</form>`);$("#catalog-edit-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;await db.update("game_catalog",r.id,{name:f.name.value,category:f.category.value,manufacturer:f.manufacturer.value,description:f.description.value,status:f.status.value,confidence:f.confidence.value,change_reason:f.reason.value});modal.close();toast("Imported record corrected and protected from source overwrite.","success");await renderCatalog(content,profile);});$("#release-catalog-override",modal.card)?.addEventListener("click",async()=>{if(!confirm("Return this record to external source control on the next import?"))return;await db.rpc("release_data_override",{table:"game_catalog",id:r.id});modal.close();toast("Record returned to source control.","success");await renderCatalog(content,profile);});}));
  };
  $("#catalog-filter").addEventListener("input",render);$("#catalog-type").addEventListener("change",render);render();
  $("#submit-location").addEventListener("click",()=>window.dispatchEvent(new CustomEvent("free-navy:navigate",{detail:"knowledge"})));
  $("#open-sync")?.addEventListener("click",()=>window.dispatchEvent(new CustomEvent("free-navy:navigate",{detail:"sync"})));
}

async function reviewApplication(application, decision, profile, refresh) {
  const labels = { approved: "Approve", refused: "Refuse", more_info: "Request more information" };
  const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">MEMBERSHIP REVIEW</p><h2>${labels[decision]} ${escapeHtml(application.display_name)}</h2><p>${escapeHtml(application.rsi_handle)} · ${escapeHtml(application.discord_handle || "No Discord handle")} · ${escapeHtml(application.email)}</p><form id="review-application-form" class="stack-form">${decision === "approved" ? `<label>Probation period (days)<input name="probation_days" type="number" min="0" max="365" value="${Number(application.probation_days ?? 14)}"></label>` : ""}<label>Review notes<textarea name="notes" rows="4" ${decision === "more_info" ? "required" : ""}></textarea></label><button class="button ${decision==="refused"?"danger":"primary"}">${labels[decision]}</button></form>`);
  $("#review-application-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();try{await db.rpc("review_membership_application",{application_id:application.id,decision,notes:e.currentTarget.notes.value,probation_days:Number(e.currentTarget.probation_days?.value ?? application.probation_days ?? 14)});modal.close();toast(decision==="approved"?"Application approved and setup email sent.":decision==="refused"?"Application refused.":"Further information request recorded.","success");await refresh();}catch(error){toast(error.message,"error",6000);}});
}

async function renderMembers(content, profile) {
  const profiles=await loadProfiles();
  const [quals, applications, departments] = await Promise.all([
    db.list("member_qualifications"),
    profile.capabilities?.approve_applications ? db.list("membership_applications",{order:"created_at"}).catch(()=>[]) : Promise.resolve([]),
    db.list("departments",{order:"sort_order",ascending:true}).catch(()=>[])
  ]);
  let privateLink=null;
  if(profile.capabilities?.view_signup_link){try{privateLink=await db.signupLink();}catch(error){privateLink={error:error.message};}}
  const rankOptions=["president","vice_president","general","admiral","vice_admiral","rear_admiral","brigadier_general","officer","enlisted"];
  const pending=applications.filter(a=>a.status==="pending");
  const activeCount=profiles.filter(p=>p.status==="active"&&p.membership_stage!=="former").length;
  content.innerHTML=`${pageHero("Member directory","Command rank, concurrent appointments, departments, probation, private applications and account security.")}
    ${profile.capabilities?.view_signup_link&&config.featureFlags?.recruitment!==false?`<section class="card pad page-section">${header("Daily private signup link","Only Officers and above can view it. The token changes each UTC day, can be revoked immediately and only opens an application form.",profile.capabilities?.manage_signup_link?`<div class="button-row"><button id="regenerate-signup-link" class="button">Regenerate</button><button id="revoke-signup-link" class="button danger">Revoke</button></div>`:"")} ${privateLink?.url?`<div class="copy-field"><input id="private-signup-link" readonly value="${escapeHtml(privateLink.url)}"><button id="copy-signup-link" class="button primary">Copy link</button></div><small class="muted">Valid ${escapeHtml(privateLink.token_date)} UTC · ${formatNumber(privateLink.uses_count)} / ${formatNumber(privateLink.max_uses)} uses · expires ${formatDate(privateLink.expires_at)}</small>`:`<div class="notice warning">${escapeHtml(privateLink?.error||"Private signup secret is not configured.")}</div>`}</section>`:""}
    ${profile.capabilities?.approve_applications&&config.featureFlags?.recruitment!==false?`<section class="card pad page-section">${header("Pending membership applications",`${pending.length} waiting for command review.`)}<div class="list">${pending.map(a=>`<div class="list-item application-item"><div><strong>${escapeHtml(a.display_name)}</strong><small>${escapeHtml(a.rsi_handle)} · ${escapeHtml(a.discord_handle||"No Discord handle")} · ${escapeHtml(a.email)}</small><small>Referred by: ${escapeHtml(a.referrer_name||"Not stated")} · Department: ${escapeHtml(a.requested_department||"No preference")}</small><p>${escapeHtml(a.message||"")}</p>${a.review_notes?`<div class="notice compact">Previous review note: ${escapeHtml(a.review_notes)}</div>`:""}</div><div class="button-row"><button class="button small primary" data-app-approve="${a.id}">Approve</button><button class="button small" data-app-more="${a.id}">Request info</button><button class="button small danger" data-app-refuse="${a.id}">Refuse</button></div></div>`).join("")||emptyState("No pending applications","The recruitment queue is clear.")}</div></section>`:""}
    ${header("Organisation roster",`${activeCount} active member${activeCount===1?"":"s"}.`,profile.capabilities?.manage_members?`<button id="invite-member" class="button primary">Direct invitation</button>`:"")}
    <div class="member-grid">${profiles.map(p=>`<article class="card pad member-card"><div class="member-heading"><div class="avatar">${escapeHtml((p.display_name||"FN").split(/\s+/).map(x=>x[0]).slice(0,2).join(""))}</div><div><h3>${escapeHtml(p.display_name)}</h3><p>${escapeHtml(p.rsi_handle||"No RSI handle")} · ${escapeHtml(p.discord_handle||"No Discord handle")}</p></div>${pill(p.status)}</div><div class="blueprint-meta"><span class="pill cyan">${escapeHtml(rankLabel(p.rank||"enlisted"))}</span>${(p.role_details||[]).map(r=>`<span class="pill amber" title="${escapeHtml(r.scope||"organisation")}${r.expires_at?` · expires ${formatDate(r.expires_at)}`:""}">${escapeHtml(roleLabel(r.role))}${r.expires_at?" ⏱":""}</span>`).join("")}<span class="pill ${p.membership_stage==="probationary"?"amber":"green"}">${escapeHtml(titleCase(p.membership_stage||"full"))}</span><span class="pill amber">${formatNumber(p.points_balance)} pts</span></div><div class="department-tags">${(p.departments||[]).map(d=>`<span class="pill">${escapeHtml(d.name)} · ${escapeHtml(titleCase(d.department_role))}</span>`).join("")||'<span class="muted">No department assigned</span>'}</div>${p.membership_stage==="probationary"?`<small class="muted">Probation ends ${formatDate(p.probation_ends_at)}</small>`:""}<div class="list">${quals.filter(q=>q.member_id===p.id).map(q=>`<div class="list-item"><div><strong>${escapeHtml(q.qualification)}</strong><small>${escapeHtml(q.notes||"")}</small></div>${pill(q.level)}</div>`).join("")||`<small class="muted">No recorded qualifications.</small>`}</div><div class="member-actions">${p.id===profile.id?`<button class="button small ghost" data-edit-profile="${p.id}">Edit my profile</button>`:""}${(profile.capabilities?.manage_members||profile.capabilities?.assign_ranks||profile.capabilities?.assign_appointments)&&p.id!==profile.id?`<button class="button small" data-manage-member="${p.id}">Manage access</button>`:""}</div></article>`).join("")}</div>`;

  $("#copy-signup-link")?.addEventListener("click",async()=>{await navigator.clipboard.writeText($("#private-signup-link").value);toast("Private signup link copied.","success");});
  $("#regenerate-signup-link")?.addEventListener("click",async()=>{const maxUses=Number(prompt("Maximum applications this link may accept:",String(privateLink?.max_uses||25))||25);try{await db.signupLink("regenerate",{max_uses:maxUses});toast("A replacement private link was generated.","success");await renderMembers(content,profile);}catch(error){toast(error.message,"error",6000);}});
  $("#revoke-signup-link")?.addEventListener("click",async()=>{if(!privateLink?.id||!confirm("Revoke the current private signup link immediately?"))return;try{await db.signupLink("revoke",{id:privateLink.id});toast("Private link revoked.","success");await renderMembers(content,profile);}catch(error){toast(error.message,"error",6000);}});
  $$('[data-app-approve]').forEach(b=>b.addEventListener("click",()=>reviewApplication(pending.find(a=>a.id===b.dataset.appApprove),"approved",profile,()=>renderMembers(content,profile))));
  $$('[data-app-more]').forEach(b=>b.addEventListener("click",()=>reviewApplication(pending.find(a=>a.id===b.dataset.appMore),"more_info",profile,()=>renderMembers(content,profile))));
  $$('[data-app-refuse]').forEach(b=>b.addEventListener("click",()=>reviewApplication(pending.find(a=>a.id===b.dataset.appRefuse),"refused",profile,()=>renderMembers(content,profile))));
  $$('[data-edit-profile]').forEach(b=>b.addEventListener("click",()=>{const p=profiles.find(x=>x.id===b.dataset.editProfile);const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">MY PROFILE</p><h2>Update member details</h2><form id="profile-form" class="stack-form"><label>Display name<input name="display_name" value="${escapeHtml(p.display_name||"")}" required></label><label>RSI handle<input name="rsi_handle" value="${escapeHtml(p.rsi_handle||"")}" required></label><label>Discord handle <span class="muted">(optional text field only)</span><input name="discord_handle" value="${escapeHtml(p.discord_handle||"")}"></label><label>Time zone<input name="time_zone" value="${escapeHtml(p.time_zone||"")}" placeholder="Europe/London"></label><label>Preferred activities<textarea name="preferred_activities">${escapeHtml(p.preferred_activities||"")}</textarea></label><label>Availability notes<textarea name="availability_notes">${escapeHtml(p.availability_notes||"")}</textarea></label><button class="button primary">Save profile</button></form>`);$("#profile-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;await db.update("profiles",p.id,{display_name:f.display_name.value,rsi_handle:f.rsi_handle.value,discord_handle:f.discord_handle.value,time_zone:f.time_zone.value,preferred_activities:f.preferred_activities.value,availability_notes:f.availability_notes.value});modal.close();toast("Profile updated.","success");await renderMembers(content,profile);});}));
  $$('[data-manage-member]').forEach(b=>b.addEventListener("click",()=>{
    const p=profiles.find(x=>x.id===b.dataset.manageMember); const canRank=profile.capabilities?.assign_ranks,canRoles=profile.capabilities?.assign_appointments,canStatus=profile.capabilities?.manage_members,canDepartments=profile.capabilities?.manage_departments;
    const roleDetail=(role)=>(p.role_details||[]).find(item=>item.role===role)||{};
    const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">MEMBER ACCESS</p><h2>${escapeHtml(p.display_name)}</h2><form id="member-access-form" class="stack-form"><label>Command rank<select name="rank" ${canRank?"":"disabled"}>${rankOptions.map(r=>`<option value="${r}" ${p.rank===r?"selected":""}>${escapeHtml(rankLabel(r))}</option>`).join("")}</select></label><fieldset ${canRoles?"":"disabled"}><legend>Concurrent appointments</legend>${["admin","quartermaster","treasurer"].map(r=>`<div class="appointment-editor"><label class="checkbox-field"><input type="checkbox" name="${r}" ${(p.roles||[]).includes(r)?"checked":""}> ${escapeHtml(roleLabel(r))}</label><label>Expires<input type="datetime-local" name="${r}_expires" value="${roleDetail(r).expires_at?new Date(roleDetail(r).expires_at).toISOString().slice(0,16):""}"></label><label>Scope<input name="${r}_scope" value="${escapeHtml(roleDetail(r).scope||"organisation")}"></label></div>`).join("")}</fieldset><div class="grid cols-2"><label>Account status<select name="status" ${canStatus?"":"disabled"}><option ${p.status==="active"?"selected":""}>active</option><option ${p.status==="inactive"?"selected":""}>inactive</option><option ${p.status==="banned"?"selected":""}>banned</option></select></label><label>Membership stage<select name="stage" ${canStatus?"":"disabled"}><option value="probationary" ${p.membership_stage==="probationary"?"selected":""}>Probationary</option><option value="full" ${p.membership_stage==="full"?"selected":""}>Full</option><option value="former" ${p.membership_stage==="former"?"selected":""}>Former</option></select></label></div><label>Probation days<input name="probation_days" type="number" min="0" max="365" value="14" ${canStatus?"":"disabled"}></label><label>Access notes<textarea name="notes">${escapeHtml(p.probation_notes||"")}</textarea></label>${canDepartments?`<fieldset><legend>Departments</legend>${departments.filter(d=>d.enabled!==false).map(d=>{const memberDept=(p.departments||[]).find(item=>item.id===d.id);return `<div class="department-editor"><label class="checkbox-field"><input type="checkbox" name="dept_${d.id}" ${memberDept?"checked":""}> ${escapeHtml(d.name)}</label><select name="dept_role_${d.id}">${["member","officer","deputy","lead"].map(v=>`<option value="${v}" ${memberDept?.department_role===v?"selected":""}>${titleCase(v)}</option>`).join("")}</select></div>`;}).join("")}</fieldset>`:""}<button class="button primary">Save access</button>${canStatus?`<div class="button-row"><button id="reset-member-password" type="button" class="button">Send password reset</button><button id="revoke-member-sessions" type="button" class="button">Revoke sessions</button><button id="remove-member" type="button" class="button danger">Remove member login</button></div>`:""}</form>`,true);
    $("#member-access-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;try{if(canRank&&f.rank.value!==p.rank)await db.rpc("set_member_rank",{target_member:p.id,rank:f.rank.value});if(canRoles)for(const r of ["admin","quartermaster","treasurer"]){const enabled=f.elements[r].checked;const old=(p.roles||[]).includes(r);const detail=roleDetail(r);const expires=f.elements[`${r}_expires`].value||null;const scope=f.elements[`${r}_scope`].value||"organisation";if(enabled!==old||enabled&&(String(expires||"")!==String(detail.expires_at?new Date(detail.expires_at).toISOString().slice(0,16):"")||scope!==String(detail.scope||"organisation")))await db.rpc("set_member_appointment",{target_member:p.id,role:r,enabled,expires_at:expires,scope,notes:f.notes.value});}if(canStatus&&f.status.value!==p.status)await db.rpc("set_member_status",{target_member:p.id,status:f.status.value});if(canStatus&&f.stage.value!==p.membership_stage)await db.rpc("set_membership_stage",{target_member:p.id,stage:f.stage.value,probation_days:Number(f.probation_days.value),notes:f.notes.value});if(canDepartments)for(const d of departments){const enabled=f.elements[`dept_${d.id}`].checked;const old=(p.departments||[]).some(item=>item.id===d.id);const role=f.elements[`dept_role_${d.id}`].value;if(enabled!==old||enabled&&role!==(p.departments||[]).find(item=>item.id===d.id)?.department_role)await db.rpc("set_member_department",{target_member:p.id,department_id:d.id,enabled,department_role:role});}modal.close();toast("Member access updated. Changes are enforced by the database immediately.","success",6000);await renderMembers(content,profile);}catch(error){toast(error.message,"error",6000);}});
    $("#reset-member-password",modal.card)?.addEventListener("click",async()=>{try{await db.rpc("send_member_password_reset",{target_member:p.id});toast("Password reset email sent.","success");}catch(error){toast(error.message,"error",6000);}});
    $("#revoke-member-sessions",modal.card)?.addEventListener("click",async()=>{if(!confirm(`Revoke all current sessions for ${p.display_name}?`))return;try{await db.rpc("revoke_member_sessions",{target_member:p.id});toast("Sessions revoked. The member must sign in again.","success");}catch(error){toast(error.message,"error",6000);}});
    $("#remove-member",modal.card)?.addEventListener("click",async()=>{if(!confirm(`Remove ${p.display_name}'s login access? Their history will be retained.`))return;await db.rpc("remove_member",{target_member:p.id});modal.close();toast("Member login removed.","success");await renderMembers(content,profile);});
  }));
  $("#invite-member")?.addEventListener("click",()=>{const ranks=profile.capabilities?.assign_ranks?rankOptions:["enlisted"];const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">DIRECT INVITATION</p><h2>Invite a Free Navy member</h2><form id="invite-form" class="stack-form"><label>Display name<input name="name" required></label><label>RSI handle<input name="rsi"></label><label>Discord handle <span class="muted">(optional text only)</span><input name="discord"></label><label>Email<input name="email" type="email" required></label><label>Starting rank<select name="rank">${ranks.map(r=>`<option value="${r}">${escapeHtml(rankLabel(r))}</option>`).join("")}</select></label><label>Probation days<input name="probation_days" type="number" min="0" max="365" value="14"></label><button class="button primary">Send invitation</button></form>`);$("#invite-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget;try{await db.inviteMember(f.email.value,f.name.value,f.rank.value,f.rsi.value,f.discord.value,Number(f.probation_days.value));modal.close();toast("Invitation created and setup email sent.","success");await renderMembers(content,profile);}catch(error){toast(error.message,"error",6000);}});});
}

async function renderSync(content, profile) {
  const [sources,runs,catalog,blueprints,flags] = await Promise.all([
    db.list("sync_sources",{order:"source_name",ascending:true}),
    db.list("data_import_runs",{order:"started_at",limit:100}).catch(()=>[]),
    db.list("game_catalog",{order:null,limit:5000}),
    db.list("blueprints",{order:null,limit:5000}),
    db.list("data_flags",{order:null}).catch(()=>[])
  ]);
  const failedSources=sources.filter(s=>s.status==="failed"||Number(s.consecutive_failures||0)>0);
  content.innerHTML=`${pageHero("LIVE source control","Checked data publishes directly to members. Failed imports preserve the previous dataset, and every real import creates a pre-import JSON snapshot.")}
    <div class="grid cols-4">${metric("Environment","LIVE","PTU/EPTU/Evocati rejected","GATE")}${metric("Patch",LIVE_PATCH,"Current operational gate","PATCH")}${metric("Catalogue",catalog.length,`${blueprints.length} blueprint records`,"DATA")}${metric("Source alerts",failedSources.length,failedSources.length?"Attention required":"Sources healthy","HEALTH")}</div>
    ${failedSources.length?`<div class="notice danger"><strong>${failedSources.length} source warning(s).</strong> Existing member-facing records remain available. Review the error and use a dry run before resuming.</div>`:""}
    <section class="card pad page-section">${header("Import controls","A dry run checks the source and rolls back all changes. A normal run first stores a pre-import backup.",`<div class="button-row"><button class="button primary" data-run-import="all">Sync all</button><button class="button" data-run-import="wiki">Wiki data</button><button class="button" data-run-import="uex">UEX data</button><button class="button ghost" data-dry-import="all">Dry run all</button><button id="check-live-version" class="button ghost">Check LIVE patch</button></div>`)}<div class="notice compact"><strong>Member-facing publication:</strong> valid LIVE records appear immediately. Zero-result protection, required-field checks, duplicate keys, environment checks and source retention prevent an empty or test-server response from replacing trusted data.</div></section>
    <section class="card pad page-section">${header("Automatic sources","Pause a source without deleting its existing published records.")}<div class="table-wrap"><table><thead><tr><th>Source</th><th>Cadence</th><th>Enabled</th><th>Paused</th><th>Auto publish</th><th>Status</th><th>Last success</th><th>Received / published / rejected</th><th>Failures</th><th>Actions</th></tr></thead><tbody>${sources.map(s=>`<tr><td>${escapeHtml(s.source_name)}</td><td>${escapeHtml(s.cadence||"—")}</td><td>${s.enabled?"Yes":"No"}</td><td>${s.paused?"Yes":"No"}</td><td>${s.auto_publish?"Yes":"No"}</td><td>${pill(s.status)}</td><td>${formatDate(s.last_success_at)}</td><td>${formatNumber(s.records_received)} / ${formatNumber(s.records_published)} / ${formatNumber(s.records_rejected)}</td><td>${formatNumber(s.consecutive_failures)}</td><td><div class="table-actions"><button class="button small" data-source-toggle="${s.id}" data-field="paused" data-value="${s.paused?"false":"true"}">${s.paused?"Resume":"Pause"}</button><button class="button small ghost" data-source-toggle="${s.id}" data-field="enabled" data-value="${s.enabled?"false":"true"}">${s.enabled?"Disable":"Enable"}</button></div></td></tr>${s.last_error?`<tr class="error-detail"><td colspan="10"><strong>${escapeHtml(s.source_name)}:</strong> ${escapeHtml(s.last_error)}</td></tr>`:""}`).join("")}</tbody></table></div></section>
    <section class="card pad page-section">${header("Recent import runs",`${runs.length} recorded run(s).`)}<div class="table-wrap"><table><thead><tr><th>Source</th><th>Trigger</th><th>Status</th><th>Received</th><th>Published</th><th>Rejected</th><th>Started</th><th>Error</th></tr></thead><tbody>${runs.map(r=>`<tr><td>${escapeHtml(r.source_name)}</td><td>${escapeHtml(r.trigger_type)}</td><td>${pill(r.status)}</td><td>${formatNumber(r.records_received)}</td><td>${formatNumber(r.records_published)}</td><td>${formatNumber(r.records_rejected)}</td><td>${formatDate(r.started_at)}</td><td>${escapeHtml(r.error_message||"—")}</td></tr>`).join("")||`<tr><td colspan="8">${emptyState("No import runs yet","Start the first LIVE data sync above.")}</td></tr>`}</tbody></table></div></section>`;
  const runImport=async(button,source,dryRun)=>{setLoading(button,true,dryRun?"Checking…":"Starting…");try{await db.runGameImport(source,dryRun);toast(dryRun?"Dry run started. No imported records will be committed.":"Pre-import backup and background sync started.","success",6500);}catch(error){toast(error.message,"error",6500);}finally{setLoading(button,false);}};
  $$('[data-run-import]').forEach(b=>b.addEventListener("click",()=>runImport(b,b.dataset.runImport,false)));
  $$('[data-dry-import]').forEach(b=>b.addEventListener("click",()=>runImport(b,b.dataset.dryImport,true)));
  $$('[data-source-toggle]').forEach(b=>b.addEventListener("click",async()=>{try{await db.update("sync_sources",b.dataset.sourceToggle,{[b.dataset.field]:b.dataset.value==="true"});toast("Source setting updated.","success");await renderSync(content,profile);}catch(error){toast(error.message,"error",6000);}}));
  $("#check-live-version").addEventListener("click",async(e)=>{setLoading(e.currentTarget,true,"Checking…");try{const result=await db.liveVersion();toast(`Official gate reports ${result.environment} ${result.version}.`,result.version===LIVE_PATCH?"success":"warning",6000);}finally{setLoading(e.currentTarget,false);}});
}

async function renderAdmin(content, profile) {
  const caps=profile.capabilities||{};
  const canSite=Boolean(caps.manage_site), canApprove=Boolean(caps.approve_applications), canEdit=Boolean(caps.edit_game_data);
  const canAnnouncements=isOfficerUp(profile)||canSite, canPermissions=Boolean(caps.manage_permissions), canDepartments=Boolean(caps.manage_departments), canFeatures=Boolean(caps.manage_features), canApprovals=Boolean(caps.manage_approvals);
  const [applications,announcements,pageContent,backgrounds,flags,audit,history,departments,features,roleOverrides,approvals,settings,blocks,profiles] = await Promise.all([
    canApprove?db.list("membership_applications",{order:"created_at"}).catch(()=>[]):Promise.resolve([]),
    db.list("announcements",{order:"created_at"}),
    canSite?db.list("page_content",{order:"page_id",ascending:true}).catch(()=>[]):Promise.resolve([]),
    canSite?db.list("page_backgrounds",{order:"page_id",ascending:true}).catch(()=>[]):Promise.resolve([]),
    canEdit?db.list("data_flags",{order:"created_at"}).catch(()=>[]):Promise.resolve([]),
    canSite?db.list("audit_log",{order:"created_at",limit:500}).catch(()=>[]):Promise.resolve([]),
    canSite?db.list("record_history",{order:"created_at",limit:500}).catch(()=>[]):Promise.resolve([]),
    canDepartments?db.list("departments",{order:"sort_order",ascending:true}).catch(()=>[]):Promise.resolve([]),
    canFeatures?db.list("feature_flags",{order:"feature_key",ascending:true}).catch(()=>[]):Promise.resolve([]),
    canPermissions?db.list("role_capability_overrides",{order:"subject_key",ascending:true}).catch(()=>[]):Promise.resolve([]),
    canApprovals?db.list("approval_requests",{order:"created_at"}).catch(()=>[]):Promise.resolve([]),
    canSite?db.list("site_settings",{order:"setting_key",ascending:true}).catch(()=>[]):Promise.resolve([]),
    canSite?db.list("recruitment_blocks",{order:"created_at"}).catch(()=>[]):Promise.resolve([]),
    loadProfiles()
  ]);
  const pending=applications.filter(a=>a.status==="pending"),openFlags=flags.filter(f=>["open","reviewing"].includes(f.status)),pendingApprovals=approvals.filter(a=>a.status==="pending");
  const capabilityLabels={manage_site:"Website management",manage_members:"Member management",approve_applications:"Application approval",view_signup_link:"View private signup link",manage_signup_link:"Manage private signup link",manage_warehouse:"Warehouse management",manage_treasury:"Treasury and points",edit_game_data:"Edit imported game data",approve_game_data:"Approve data corrections",manage_operations:"Operations management",manage_training:"Training management",manage_departments:"Department management",manage_imports:"Data import controls",manage_features:"Feature switches",manage_backups:"JSON backups",manage_knowledge:"Knowledge-base editing",manage_approvals:"Second-person approvals"};
  const permissionSubjects=[...['president','vice_president','general','admiral','vice_admiral','rear_admiral','brigadier_general','officer','enlisted'].map(key=>({type:'rank',key,label:rankLabel(key)})),...['admin','quartermaster','treasurer'].map(key=>({type:'appointment',key,label:roleLabel(key)}))];
  const defaultPermission=(subject,capability)=>{const rank=subject.type==='rank'?subject.key:null,role=subject.type==='appointment'?subject.key:null;const executive=['president','vice_president'].includes(rank),officer=['president','vice_president','general','admiral','vice_admiral','rear_admiral','brigadier_general','officer'].includes(rank);const admin=role==='admin',quartermaster=role==='quartermaster',treasurer=role==='treasurer';return ({manage_site:executive||admin,manage_members:executive||admin,approve_applications:officer||admin,view_signup_link:officer,manage_signup_link:officer,manage_warehouse:executive||quartermaster,manage_treasury:executive||treasurer,edit_game_data:officer||admin,approve_game_data:officer||admin,manage_operations:officer,manage_training:officer,manage_departments:executive||admin,manage_imports:officer||admin,manage_features:executive||admin,manage_backups:executive||admin,manage_knowledge:officer||admin,manage_approvals:executive||quartermaster||treasurer})[capability]||false;};
  const overrideFor=(subject,capability)=>roleOverrides.find(row=>row.subject_type===subject.type&&row.subject_key===subject.key&&row.capability===capability);
  content.innerHTML=`${pageHero("Admin and command control","Manage recruitment, permissions, departments, feature switches, content, accuracy reports and site governance without opening the database console.")}
    ${canApprove&&config.featureFlags?.recruitment!==false?`<section class="card pad page-section">${header("Membership approvals",`${pending.length} pending application(s).`)}<div class="list">${pending.map(a=>`<div class="list-item"><div><strong>${escapeHtml(a.display_name)}</strong><small>${escapeHtml(a.rsi_handle)} · ${escapeHtml(a.discord_handle||"No Discord handle")} · ${escapeHtml(a.email)}</small><small>Referrer: ${escapeHtml(a.referrer_name||"Not stated")} · Department: ${escapeHtml(a.requested_department||"No preference")}</small><p>${escapeHtml(a.message||"")}</p>${a.review_notes?`<div class="notice compact">${escapeHtml(a.review_notes)}</div>`:""}</div><div class="button-row"><button class="button small primary" data-admin-approve="${a.id}">Approve</button><button class="button small" data-admin-more="${a.id}">Request info</button><button class="button small danger" data-admin-refuse="${a.id}">Refuse</button></div></div>`).join("")||emptyState("No pending applications","The recruitment queue is clear.")}</div></section>`:""}
    ${canApprovals?`<section class="card pad page-section">${header("Second-person approvals",`${pendingApprovals.length} high-value action(s) waiting for another authorised user.`)}<div class="table-wrap"><table><thead><tr><th>Request</th><th>Type</th><th>Requested by</th><th>Created</th><th>Actions</th></tr></thead><tbody>${pendingApprovals.map(a=>`<tr><td>${escapeHtml(a.title)}</td><td>${escapeHtml(titleCase(a.request_type))}</td><td>${escapeHtml(profileName(a.requested_by))}</td><td>${formatDate(a.created_at)}</td><td><div class="table-actions"><button class="button small primary" data-approval="${a.id}" data-decision="approved">Approve</button><button class="button small danger" data-approval="${a.id}" data-decision="rejected">Reject</button></div></td></tr>`).join("")||`<tr><td colspan="5">${emptyState("No pending approvals","High-value controls are clear.")}</td></tr>`}</tbody></table></div></section>`:""}
    ${canSite&&config.featureFlags?.recruitment!==false?`<section class="card pad page-section">${header("Recruitment blocks",`${blocks.length} blocked email address${blocks.length===1?"":"es"}.`,`<button id="add-recruitment-block" class="button danger">Block email</button>`)}<div class="table-wrap"><table><thead><tr><th>Email</th><th>Reason</th><th>Added by</th><th>Date</th><th>Action</th></tr></thead><tbody>${blocks.map(block=>`<tr><td>${escapeHtml(block.email)}</td><td>${escapeHtml(block.reason||"—")}</td><td>${escapeHtml(profileName(block.created_by))}</td><td>${formatDate(block.created_at)}</td><td><button class="button small ghost" data-remove-recruitment-block="${block.id}">Remove block</button></td></tr>`).join("")||`<tr><td colspan="5">${emptyState("No blocked emails","Recruitment blocks are empty.")}</td></tr>`}</tbody></table></div></section>`:""}
    <section class="card pad page-section">${header("Announcements",`${announcements.length} organisation announcement(s).`,canAnnouncements?`<button id="add-announcement" class="button primary">Add announcement</button>`:"")}<div class="list">${announcements.map(a=>`<div class="list-item"><div><strong>${escapeHtml(a.title)}</strong><small>${escapeHtml(a.body||"")}</small></div><div class="button-row">${pill(a.priority)}${canAnnouncements?`<button class="button small ghost" data-edit-announcement="${a.id}">Edit</button><button class="button small danger" data-delete-announcement="${a.id}">Delete</button>`:""}</div></div>`).join("")||emptyState("No announcements","Add the first organisation announcement.")}</div></section>
    ${canEdit?`<section class="card pad page-section">${header("Accuracy flags",`${openFlags.length} open or reviewing report(s).`)}<div class="table-wrap"><table><thead><tr><th>Record</th><th>Reason</th><th>Explanation</th><th>Suggested correction</th><th>Evidence</th><th>Reporter</th><th>Actions</th></tr></thead><tbody>${openFlags.map(f=>`<tr><td>${escapeHtml(f.target_name||f.target_id)}<small class="table-subtext">${escapeHtml(f.target_table)}</small></td><td>${escapeHtml(f.reason)}</td><td>${escapeHtml(f.explanation)}</td><td>${escapeHtml(f.suggested_correction||"—")}</td><td>${f.evidence_url?`<a href="${escapeHtml(f.evidence_url)}" target="_blank" rel="noreferrer">Open</a>`:"—"}</td><td>${escapeHtml(profileName(f.reported_by))}</td><td><div class="table-actions"><button class="button small" data-flag-review="${f.id}">Review</button><button class="button small primary" data-flag-resolve="${f.id}">Resolve</button><button class="button small danger" data-flag-reject="${f.id}">Reject</button></div></td></tr>`).join("")||`<tr><td colspan="7">${emptyState("No accuracy flags","The data review queue is clear.")}</td></tr>`}</tbody></table></div></section>`:""}
    ${canPermissions?`<section class="card pad page-section">${header("Permission matrix","President and Vice President can override non-protected capabilities. Rank and concurrent appointments are evaluated together.")}<div class="notice compact"><strong>Protected controls:</strong> assigning ranks, assigning appointments, Identity administration and full backup restoration remain hard-locked to executive rank.</div><div class="permission-matrix">${permissionSubjects.map(subject=>`<article class="permission-subject"><h3>${escapeHtml(subject.label)}</h3><p class="eyebrow">${escapeHtml(subject.type)}</p>${Object.entries(capabilityLabels).map(([key,label])=>{const override=overrideFor(subject,key),effective=override?override.enabled:defaultPermission(subject,key);return `<div class="permission-row"><span>${escapeHtml(label)}</span><span class="pill ${effective?'green':'red'}">${effective?'Allowed':'Denied'}</span><select data-permission-subject-type="${subject.type}" data-permission-subject-key="${subject.key}" data-permission-capability="${key}"><option value="default" ${!override?'selected':''}>Use default</option><option value="allow" ${override?.enabled===true?'selected':''}>Allow</option><option value="deny" ${override?.enabled===false?'selected':''}>Deny</option></select></div>`;}).join("")}</article>`).join("")}</div><div class="test-permissions"><label>Preview a member's effective permissions<select id="permission-preview-member">${profiles.map(p=>`<option value="${p.id}">${escapeHtml(p.display_name)} · ${escapeHtml(rankLabel(p.rank))}</option>`).join("")}</select></label><div id="permission-preview-result"></div></div></section>`:""}
    ${canDepartments?`<section class="card pad page-section">${header("Departments","Create departments and assign leads without changing organisation rank.",`<button id="add-department" class="button primary">Add department</button>`)}<div class="grid cols-3">${departments.map(d=>`<article class="card inset-card"><div class="card-topline"><div><h3>${escapeHtml(d.name)}</h3><p>${escapeHtml(d.description||"")}</p></div>${d.enabled?'<span class="pill green">Enabled</span>':'<span class="pill red">Hidden</span>'}</div><small>Lead: ${escapeHtml(profileName(d.lead_member_id))} · Deputy: ${escapeHtml(profileName(d.deputy_member_id))}</small><button class="button small ghost" data-edit-department="${d.id}">Edit</button></article>`).join("")}</div></section>`:""}
    ${canFeatures?`<section class="card pad page-section">${header("Feature switches","Enabled modules appear in navigation immediately. Disabled modules are hidden and direct page access returns to the dashboard. Discord remains off until its Netlify setup validates.")}<div class="feature-grid">${features.map(f=>{const discord=String(f.feature_key).startsWith('discord_');return `<label class="feature-switch ${discord?'fn-discord-feature':''}"><input type="checkbox" ${discord?`data-discord-feature="${escapeHtml(f.feature_key)}"`:`data-feature-toggle="${f.id}" data-feature-key="${escapeHtml(f.feature_key)}"`} ${f.enabled?'checked':''}><span><strong>${escapeHtml(f.label)}</strong><small>${escapeHtml(f.description||'')}</small></span>${discord?'<span class="pill">Setup required</span>':`<span class="pill ${f.enabled?'green':'red'}">${f.enabled?'Enabled':'Disabled'}</span>`}</label>`;}).join("")}</div></section>`:""}
    ${canSite?`<div class="grid cols-2 page-section"><section class="card pad">${header("Page content management","Add or edit organisation-owned text blocks shown above member-facing pages.",`<button id="add-page-content" class="button">Add content block</button>`)}<div class="list">${pageContent.map(r=>`<div class="list-item"><div><strong>${escapeHtml(r.page_id)} · ${escapeHtml(r.section_key)}</strong><small>${escapeHtml(r.title)} · ${r.enabled?"Enabled":"Disabled"}</small></div><button class="button small ghost" data-edit-content="${r.id}">Edit</button></div>`).join("")||emptyState("No custom content","Default page copy is currently in use.")}</div></section><section class="card pad">${header("Background settings","Override a page background path, focus position and readability overlay.",`<button id="add-background" class="button">Add background override</button>`)}<div class="list">${backgrounds.map(r=>`<div class="list-item"><div><strong>${escapeHtml(r.page_id)}</strong><small>${escapeHtml(r.asset_path)} · ${escapeHtml(r.position)} · overlay ${r.overlay_strength}</small></div><button class="button small ghost" data-edit-background="${r.id}">Edit</button></div>`).join("")||emptyState("No overrides","The backgrounds from config.js are in use.")}</div></section></div>
    <section class="card pad page-section">${header("Safety thresholds","Configure values that require a second authorised approval.")}<div class="grid cols-3">${settings.filter(s=>['high_value_warehouse_threshold','high_value_points_threshold','default_probation_days','backup_retention'].includes(s.setting_key)).map(s=>`<article class="setting-card"><strong>${escapeHtml(titleCase(s.setting_key))}</strong><code>${escapeHtml(JSON.stringify(s.setting_value))}</code><p>${escapeHtml(s.description||'')}</p><button class="button small ghost" data-edit-setting="${s.id}">Edit JSON value</button></article>`).join("")}</div></section>
    <section class="card pad page-section">${header("Audit and record history",`${audit.length} audit event(s) and ${history.length} detailed revision(s).`)}<div class="tabs-inline"><button class="button small" data-audit-view="audit">Audit log</button><button class="button small ghost" data-audit-view="history">Record revisions</button></div><div id="admin-audit-table"><div class="table-wrap"><table><thead><tr><th>Actor</th><th>Action</th><th>Entity</th><th>Name</th><th>Date</th></tr></thead><tbody>${audit.map(a=>`<tr><td>${escapeHtml(profileName(a.actor_id))}</td><td class="mono">${escapeHtml(a.action)}</td><td>${escapeHtml(a.entity_type)}</td><td>${escapeHtml(a.entity_name)}</td><td>${formatDate(a.created_at)}</td></tr>`).join("")}</tbody></table></div></div></section>`:""}`;

  $$('[data-admin-approve]').forEach(b=>b.addEventListener("click",()=>reviewApplication(pending.find(a=>a.id===b.dataset.adminApprove),"approved",profile,()=>renderAdmin(content,profile))));
  $$('[data-admin-more]').forEach(b=>b.addEventListener("click",()=>reviewApplication(pending.find(a=>a.id===b.dataset.adminMore),"more_info",profile,()=>renderAdmin(content,profile))));
  $$('[data-admin-refuse]').forEach(b=>b.addEventListener("click",()=>reviewApplication(pending.find(a=>a.id===b.dataset.adminRefuse),"refused",profile,()=>renderAdmin(content,profile))));
  $$('[data-approval]').forEach(b=>b.addEventListener("click",async()=>{const notes=prompt("Review notes:","")||"";try{await db.rpc("review_approval_request",{request_id:b.dataset.approval,decision:b.dataset.decision,notes});toast(`Approval request ${b.dataset.decision}.`,"success");await renderAdmin(content,profile);}catch(error){toast(error.message,"error",6000);}}));
  const announcementForm=(existing=null)=>{const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">ANNOUNCEMENT</p><h2>${existing?"Edit":"Add"} announcement</h2><form id="announcement-form" class="stack-form"><label>Title<input name="title" value="${escapeHtml(existing?.title||"")}" required></label><label>Message<textarea name="body" rows="5" required>${escapeHtml(existing?.body||"")}</textarea></label><label>Priority<select name="priority"><option ${existing?.priority==="normal"?"selected":""}>normal</option><option ${existing?.priority==="important"?"selected":""}>important</option><option ${existing?.priority==="critical"?"selected":""}>critical</option></select></label><button class="button primary">Save announcement</button></form>`);$("#announcement-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget,payload={title:f.title.value,body:f.body.value,priority:f.priority.value};existing?await db.update("announcements",existing.id,payload):await db.create("announcements",payload);modal.close();toast("Announcement saved.","success");await renderAdmin(content,profile);});};
  $("#add-recruitment-block")?.addEventListener("click",()=>{const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">RECRUITMENT SECURITY</p><h2>Block an email address</h2><form id="recruitment-block-form" class="stack-form"><label>Email<input name="email" type="email" required></label><label>Reason<textarea name="reason" rows="4" required></textarea></label><button class="button danger">Block application access</button></form>`);$("#recruitment-block-form",modal.card).addEventListener("submit",async(event)=>{event.preventDefault();const form=event.currentTarget;try{await db.create("recruitment_blocks",{email:form.email.value.trim().toLowerCase(),reason:form.reason.value.trim(),created_by:profile.id});modal.close();toast("Email blocked from private applications.","success");await renderAdmin(content,profile);}catch(error){toast(error.message,"error",6000);}});});
  $$('[data-remove-recruitment-block]').forEach(button=>button.addEventListener("click",async()=>{if(!confirm("Remove this recruitment block?"))return;try{await db.remove("recruitment_blocks",button.dataset.removeRecruitmentBlock);toast("Recruitment block removed.","success");await renderAdmin(content,profile);}catch(error){toast(error.message,"error",6000);}}));
  $("#add-announcement")?.addEventListener("click",()=>announcementForm());$$('[data-edit-announcement]').forEach(b=>b.addEventListener("click",()=>announcementForm(announcements.find(a=>a.id===b.dataset.editAnnouncement))));$$('[data-delete-announcement]').forEach(b=>b.addEventListener("click",async()=>{if(confirm("Delete this announcement?")){await db.remove("announcements",b.dataset.deleteAnnouncement);await renderAdmin(content,profile);}}));
  const resolveFlag=async(id,status)=>{const notes=prompt("Resolution notes:","")||"";await db.rpc("resolve_data_flag",{flag_id:id,status,resolution_notes:notes});toast("Accuracy report updated.","success");await renderAdmin(content,profile);};$$('[data-flag-review]').forEach(b=>b.addEventListener("click",()=>resolveFlag(b.dataset.flagReview,"reviewing")));$$('[data-flag-resolve]').forEach(b=>b.addEventListener("click",()=>resolveFlag(b.dataset.flagResolve,"resolved")));$$('[data-flag-reject]').forEach(b=>b.addEventListener("click",()=>resolveFlag(b.dataset.flagReject,"rejected")));
  $$('[data-permission-capability]').forEach(select=>select.addEventListener("change",async()=>{const value=select.value;try{await db.rpc("set_capability_override",{subject_type:select.dataset.permissionSubjectType,subject_key:select.dataset.permissionSubjectKey,capability:select.dataset.permissionCapability,remove:value==="default",enabled:value==="allow"});toast("Permission matrix updated.","success");await renderAdmin(content,profile);}catch(error){toast(error.message,"error",6000);}}));
  const renderPermissionPreview=()=>{const member=profiles.find(p=>p.id===$("#permission-preview-member")?.value);if(!member)return;const subjects=[{type:"rank",key:member.rank,label:rankLabel(member.rank)},...(member.roles||[]).map(key=>({type:"appointment",key,label:roleLabel(key)}))];const effective={};for(const key of Object.keys(capabilityLabels)){effective[key]=subjects.some(subject=>defaultPermission(subject,key));for(const subject of subjects){const override=overrideFor(subject,key);if(override)effective[key]=Boolean(override.enabled);}}$("#permission-preview-result").innerHTML=`<div class="permission-preview"><strong>${escapeHtml(member.display_name)}</strong><span>${escapeHtml(rankLabel(member.rank))}${(member.roles||[]).length?` · ${escapeHtml((member.roles||[]).map(roleLabel).join(' · '))}`:''}</span><div class="button-row">${Object.entries(effective).filter(([,v])=>v).map(([k])=>`<span class="pill green">${escapeHtml(titleCase(k))}</span>`).join('')||'<span class="muted">No elevated permissions.</span>'}</div></div>`;};$("#permission-preview-member")?.addEventListener("change",renderPermissionPreview);renderPermissionPreview();
  const departmentForm=(existing=null)=>{const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">DEPARTMENT</p><h2>${existing?"Edit":"Add"} department</h2><form id="department-form" class="stack-form"><label>Name<input name="name" value="${escapeHtml(existing?.name||'')}" required></label><label>Description<textarea name="description">${escapeHtml(existing?.description||'')}</textarea></label><label>Lead<select name="lead"><option value="">Unassigned</option>${profiles.map(p=>`<option value="${p.id}" ${existing?.lead_member_id===p.id?'selected':''}>${escapeHtml(p.display_name)}</option>`).join('')}</select></label><label>Deputy<select name="deputy"><option value="">Unassigned</option>${profiles.map(p=>`<option value="${p.id}" ${existing?.deputy_member_id===p.id?'selected':''}>${escapeHtml(p.display_name)}</option>`).join('')}</select></label><label>Sort order<input name="sort_order" type="number" value="${existing?.sort_order??100}"></label><label class="checkbox-field"><input name="enabled" type="checkbox" ${existing?.enabled===false?'':'checked'}> Enabled</label><button class="button primary">Save department</button></form>`);$("#department-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget,payload={name:f.name.value,description:f.description.value,lead_member_id:f.lead.value||null,deputy_member_id:f.deputy.value||null,sort_order:Number(f.sort_order.value),enabled:f.enabled.checked};existing?await db.update("departments",existing.id,payload):await db.create("departments",payload);modal.close();toast("Department saved.","success");await renderAdmin(content,profile);});};$("#add-department")?.addEventListener("click",()=>departmentForm());$$('[data-edit-department]').forEach(b=>b.addEventListener("click",()=>departmentForm(departments.find(d=>d.id===b.dataset.editDepartment))));
  $$('[data-feature-toggle]').forEach(input=>input.addEventListener("change",async()=>{const desired=input.checked;try{await db.update("feature_flags",input.dataset.featureToggle,{enabled:desired});config.featureFlags={...(config.featureFlags||{}),[input.dataset.featureKey]:desired};window.dispatchEvent(new CustomEvent("free-navy:feature-flags-changed",{detail:{featureKey:input.dataset.featureKey,enabled:desired}}));toast(`${desired?"Enabled":"Disabled"} ${input.closest(".feature-switch")?.querySelector("strong")?.textContent||"module"}.`,"success");await renderAdmin(content,profile);}catch(error){input.checked=!desired;toast(error.message,"error",6000);}}));
  const contentForm=(existing=null)=>{const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">PAGE CONTENT</p><h2>${existing?"Edit":"Add"} content block</h2><form id="content-form" class="stack-form"><label>Page ID<input name="page_id" value="${escapeHtml(existing?.page_id||"")}" required placeholder="dashboard"></label><label>Section key<input name="section_key" value="${escapeHtml(existing?.section_key||"intro")}" required></label><label>Title<input name="title" value="${escapeHtml(existing?.title||"")}"></label><label>Body<textarea name="body" rows="5">${escapeHtml(existing?.body||"")}</textarea></label><label class="checkbox-field"><input name="enabled" type="checkbox" ${existing?.enabled===false?"":"checked"}> Enabled</label><button class="button primary">Save content</button></form>`);$("#content-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget,payload={page_id:f.page_id.value,section_key:f.section_key.value,title:f.title.value,body:f.body.value,enabled:f.enabled.checked,updated_by:profile.id};existing?await db.update("page_content",existing.id,payload):await db.create("page_content",payload);modal.close();toast("Page content saved.","success");await renderAdmin(content,profile);});};$("#add-page-content")?.addEventListener("click",()=>contentForm());$$('[data-edit-content]').forEach(b=>b.addEventListener("click",()=>contentForm(pageContent.find(r=>r.id===b.dataset.editContent))));
  const backgroundForm=(existing=null)=>{const modal=openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">PAGE BACKGROUND</p><h2>${existing?"Edit":"Add"} background override</h2><form id="background-form" class="stack-form"><label>Page ID<input name="page_id" value="${escapeHtml(existing?.page_id||"")}" required></label><label>Local asset path<input name="asset_path" value="${escapeHtml(existing?.asset_path||"/assets/backgrounds/")}" required></label><label>Position<input name="position" value="${escapeHtml(existing?.position||"center")}"></label><label>Overlay strength<input name="overlay_strength" type="number" min="0" max="1" step="0.01" value="${existing?.overlay_strength??0.78}"></label><button class="button primary">Save background</button></form>`);$("#background-form",modal.card).addEventListener("submit",async(e)=>{e.preventDefault();const f=e.currentTarget,payload={page_id:f.page_id.value,asset_path:f.asset_path.value,position:f.position.value,overlay_strength:Number(f.overlay_strength.value),updated_by:profile.id};existing?await db.update("page_backgrounds",existing.id,payload):await db.create("page_backgrounds",payload);modal.close();toast("Background setting saved. Refresh after returning to the page.","success");await renderAdmin(content,profile);});};$("#add-background")?.addEventListener("click",()=>backgroundForm());$$('[data-edit-background]').forEach(b=>b.addEventListener("click",()=>backgroundForm(backgrounds.find(r=>r.id===b.dataset.editBackground))));
  $$('[data-edit-setting]').forEach(b=>b.addEventListener("click",()=>{const setting=settings.find(s=>s.id===b.dataset.editSetting);const value=prompt(`Edit JSON for ${setting.setting_key}:`,JSON.stringify(setting.setting_value));if(value==null)return;try{const parsed=JSON.parse(value);db.update("site_settings",setting.id,{setting_value:parsed}).then(()=>{toast("Site setting updated.","success");renderAdmin(content,profile);}).catch(error=>toast(error.message,"error",6000));}catch{toast("Enter valid JSON, for example {\"points\":5000}.","error");}}));
  $$('[data-audit-view]').forEach(b=>b.addEventListener("click",()=>{const historyView=b.dataset.auditView==="history";$("#admin-audit-table").innerHTML=historyView?`<div class="table-wrap"><table><thead><tr><th>Actor</th><th>Action</th><th>Entity</th><th>Reason</th><th>Patch</th><th>Date</th></tr></thead><tbody>${history.map(h=>`<tr><td>${escapeHtml(profileName(h.actor_id))}</td><td>${escapeHtml(h.action)}</td><td>${escapeHtml(h.entity_type)} · ${escapeHtml(h.entity_id)}</td><td>${escapeHtml(h.reason||'—')}</td><td>${escapeHtml(h.game_version||'—')}</td><td>${formatDate(h.created_at)}</td></tr>`).join('')}</tbody></table></div>`:`<div class="table-wrap"><table><thead><tr><th>Actor</th><th>Action</th><th>Entity</th><th>Name</th><th>Date</th></tr></thead><tbody>${audit.map(a=>`<tr><td>${escapeHtml(profileName(a.actor_id))}</td><td class="mono">${escapeHtml(a.action)}</td><td>${escapeHtml(a.entity_type)}</td><td>${escapeHtml(a.entity_name)}</td><td>${formatDate(a.created_at)}</td></tr>`).join('')}</tbody></table></div>`;}));
}

async function renderBackup(content, profile) {
  const backups=await db.listBackups().catch(()=>[]);
  const canRestore=Boolean(profile.capabilities?.restore_backups);
  content.innerHTML=`${pageHero("JSON backup and recovery","Stored backups live in Netlify Blobs and are tracked separately from the main Admin console.")}
    <div class="grid cols-4">${metric("Stored",backups.filter(b=>b.status==="completed").length,"Completed backup files","FILES")}${metric("Rows",formatNumber(backups.reduce((sum,b)=>sum+Number(b.row_count||0),0)),"Across retained snapshots","ROWS")}${metric("Latest",backups[0]?formatDate(backups[0].created_at,false):"None","Most recent backup","DATE")}${metric("Restore",canRestore?"President":"Read only",canRestore?"Destructive restore protected":"Download and preview only","LOCK")}</div>
    <section class="card pad page-section">${header("Create backup","Manual backups contain database records but exclude passwords, Identity secrets and environment variables.",`<button id="create-stored-backup" class="button primary">Create stored backup</button>`)}<p class="fine-print">Daily and weekly backups run automatically. Pre-import backups are created before manual data imports.</p></section>
    <section class="card pad page-section">${header("Stored backups",`${backups.length} backup record(s).`)}<div class="table-wrap"><table><thead><tr><th>Type</th><th>Status</th><th>Tables</th><th>Rows</th><th>Size</th><th>Checksum</th><th>Created</th><th>Actions</th></tr></thead><tbody>${backups.map(b=>`<tr><td>${escapeHtml(titleCase(b.backup_type))}</td><td>${pill(b.status)}</td><td>${formatNumber(b.table_count)}</td><td>${formatNumber(b.row_count)}</td><td>${formatNumber(Number(b.size_bytes||0)/1024,1)} KB</td><td class="mono">${escapeHtml((b.checksum||"").slice(0,12)||"—")}</td><td>${formatDate(b.created_at)}</td><td><div class="table-actions">${b.status==="completed"?`<a class="button small" href="${escapeHtml(db.backupDownloadUrl(b.backup_key))}">Download</a><button class="button small ghost" data-preview-backup="${b.backup_key}">Preview</button>${canRestore?`<button class="button small danger" data-restore-backup="${b.backup_key}">Restore</button><button class="button small ghost" data-delete-backup="${b.backup_key}">Delete</button>`:""}`:""}</div></td></tr>`).join("")||`<tr><td colspan="8">${emptyState("No stored backups","Create the first manual backup above.")}</td></tr>`}</tbody></table></div></section>
    <section class="card pad page-section">${header("Local one-click export","Creates a browser download from the current database snapshot for offline safekeeping.")}<button id="export-full-backup" class="button">Download immediate JSON export</button></section>`;
  $("#create-stored-backup")?.addEventListener("click",async(e)=>{setLoading(e.currentTarget,true,"Creating…");try{await db.backupAction("create");toast("Stored JSON backup completed.","success");await renderBackup(content,profile);}catch(error){toast(error.message,"error",7000);}finally{setLoading(e.currentTarget,false);}});
  $$('[data-preview-backup]').forEach(b=>b.addEventListener("click",async()=>{try{const preview=await db.backupAction("preview",{key:b.dataset.previewBackup});openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">BACKUP PREVIEW</p><h2>${escapeHtml(preview.metadata?.created_at||"Stored backup")}</h2><div class="table-wrap"><table><thead><tr><th>Table</th><th>Rows</th></tr></thead><tbody>${Object.entries(preview.tables||{}).map(([table,count])=>`<tr><td>${escapeHtml(table)}</td><td>${formatNumber(count)}</td></tr>`).join("")}</tbody></table></div>`,true);}catch(error){toast(error.message,"error",7000);}}));
  $$('[data-restore-backup]').forEach(b=>b.addEventListener("click",async()=>{const confirmation=prompt("This merges backed-up records into production. Type RESTORE FREE NAVY to continue:","");if(confirmation!=="RESTORE FREE NAVY")return;try{await db.backupAction("restore",{key:b.dataset.restoreBackup,confirmation});toast("Backup restore completed. Refresh all portal sessions.","success",8000);await renderBackup(content,profile);}catch(error){toast(error.message,"error",8000);}}));
  $$('[data-delete-backup]').forEach(b=>b.addEventListener("click",async()=>{if(!confirm("Delete this stored backup file?"))return;try{await db.backupAction("delete",{key:b.dataset.deleteBackup});toast("Backup deleted.","success");await renderBackup(content,profile);}catch(error){toast(error.message,"error",7000);}}));
  $("#export-full-backup").addEventListener("click",async(e)=>{setLoading(e.currentTarget,true,"Preparing…");try{const data=await db.backup();downloadJson(`free-navy-full-backup-${new Date().toISOString().slice(0,10)}.json`,data);toast("Local backup downloaded.","success");}catch(error){toast(error.message,"error",6000);}finally{setLoading(e.currentTarget,false);}});
}


async function renderWatchlist(content, profile) {
  const watches = await db.list("watchlists", { order: "created_at", ascending: false }).catch(() => []);
  const pageByTable = {
    warehouse_items: "warehouse", work_orders: "workorders", blueprints: "crafting", refinery_jobs: "refinery",
    knowledge_locations: "knowledge", mining_locations: "mining", salvage_locations: "salvaging", wreck_reports: "salvaging",
    game_catalog: "catalog", catalog_locations: "catalog", market_listings: "market", auctions: "auctions",
    operations: "operations", fleet_ships: "fleet", knowledge_articles: "knowledgebase"
  };
  content.innerHTML = `${pageHero("My watchlist","Follow ships, components, materials, locations, blueprints and organisation records without hunting through every page.")}
    ${header("Followed records",`${watches.length} watched record${watches.length === 1 ? "" : "s"}.`)}
    <div class="grid cols-3">${watches.map((watch) => `<article class="card pad watch-card"><div class="card-topline"><div><p class="eyebrow">${escapeHtml(titleCase(watch.entity_type))}</p><h3>${escapeHtml(watch.entity_name)}</h3></div><span class="pill cyan">WATCHING</span></div><p class="muted">Alerts: ${escapeHtml((watch.alert_types || ["changed"]).map(titleCase).join(", "))}</p><div class="button-row">${pageByTable[watch.entity_type] ? `<button class="button small" data-go="${pageByTable[watch.entity_type]}">Open module</button>` : ""}<button class="button small danger" data-unwatch="${watch.entity_type}" data-id="${escapeHtml(watch.entity_id)}" data-name="${escapeHtml(watch.entity_name)}">Remove</button></div></article>`).join("") || emptyState("Nothing watched yet","Use the Watch button beside any member-facing data record.")}</div>`;
  bindGoButtons();
  $$('[data-unwatch]').forEach((button) => button.addEventListener("click", async () => {
    try {
      await db.rpc("toggle_watchlist", { entity_type: button.dataset.unwatch, entity_id: button.dataset.id, entity_name: button.dataset.name });
      toast("Removed from your watchlist.", "success");
      await renderWatchlist(content, profile);
    } catch (error) { toast(error.message, "error", 6000); }
  }));
}

async function renderVerification(content, profile) {
  const [campaigns, tasks] = await Promise.all([
    db.list("verification_campaigns", { order: "started_at", ascending: false }).catch(() => []),
    db.list("verification_tasks", { order: "created_at", ascending: false }).catch(() => [])
  ]);
  const active = campaigns.find((campaign) => campaign.status === "active");
  const activeTasks = active ? tasks.filter((task) => task.campaign_id === active.id) : [];
  const complete = activeTasks.filter((task) => task.status === "confirmed").length;
  content.innerHTML = `${pageHero("LIVE verification campaign","After a LIVE patch change, Free Navy can reconfirm shops, mining sites and salvage locations while keeping the previous data visible.")}
    <div class="grid cols-4">${metric("Campaign",active ? active.title : "None",active ? `Alpha ${active.game_version}` : "No campaign active","LIVE")}${metric("Open",activeTasks.filter(t=>t.status==="open").length,"Available verification jobs","OPEN")}${metric("Claimed",activeTasks.filter(t=>t.status==="claimed").length,"Being checked in game","CLAIM")}${metric("Confirmed",complete,activeTasks.length ? `${Math.round((complete/activeTasks.length)*100)}% complete` : "No tasks","OK")}</div>
    ${profile.capabilities?.edit_game_data ? `<section class="card pad page-section">${header("Campaign controls","Create or refresh the current LIVE reconfirmation campaign.",`<button id="create-verification-campaign" class="button primary">Create ${escapeHtml(LIVE_PATCH)} campaign</button>`)}</section>` : ""}
    <section class="card pad page-section">${header("Verification tasks",`${activeTasks.length} task(s) in the active campaign.`)}<div class="table-wrap"><table><thead><tr><th>Record</th><th>Category</th><th>Status</th><th>Claimed by</th><th>Reward</th><th>Evidence</th><th>Action</th></tr></thead><tbody>${activeTasks.map((task) => `<tr><td>${escapeHtml(task.entity_name)}</td><td>${escapeHtml(titleCase(task.category || task.entity_type))}</td><td>${pill(task.status)}</td><td>${escapeHtml(profileName(task.claimed_by))}</td><td>${formatNumber(task.reward_points)} pts</td><td>${task.evidence_url ? `<a href="${escapeHtml(task.evidence_url)}" target="_blank" rel="noreferrer">Evidence</a>` : "—"}</td><td><div class="table-actions">${task.status === "open" ? `<button class="button small" data-claim-verification="${task.id}">Claim</button>` : ""}${task.status === "claimed" && (task.claimed_by === profile.id || profile.capabilities?.edit_game_data) ? `<button class="button small primary" data-complete-verification="${task.id}">Confirm</button>` : ""}</div></td></tr>`).join("") || `<tr><td colspan="7">${emptyState("No verification tasks","Create a campaign after a LIVE patch change or when locations need reconfirming.")}</td></tr>`}</tbody></table></div></section>`;
  $("#create-verification-campaign")?.addEventListener("click", async (event) => {
    setLoading(event.currentTarget, true, "Creating…");
    try { const result = await db.rpc("create_verification_campaign", { title: `Free Navy Alpha ${LIVE_PATCH} LIVE verification` }); toast(`${result.tasks_created} verification tasks prepared.`, "success"); await renderVerification(content, profile); }
    catch (error) { toast(error.message, "error", 6000); }
    finally { setLoading(event.currentTarget, false); }
  });
  $$('[data-claim-verification]').forEach((button) => button.addEventListener("click", async () => {
    try { await db.rpc("claim_verification_task", { task_id: button.dataset.claimVerification }); toast("Verification task claimed.", "success"); await renderVerification(content, profile); }
    catch (error) { toast(error.message, "error", 6000); }
  }));
  $$('[data-complete-verification]').forEach((button) => button.addEventListener("click", () => {
    const modal = openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">LIVE CONFIRMATION</p><h2>Confirm this record</h2><form id="verification-form" class="stack-form"><label>Evidence URL<input name="evidence_url" type="url" placeholder="Screenshot or clip"></label><label>What did you confirm?<textarea name="notes" rows="5" required></textarea></label><button class="button primary">Complete verification</button></form>`);
    $("#verification-form", modal.card).addEventListener("submit", async (event) => { event.preventDefault(); const form = event.currentTarget; try { await db.rpc("complete_verification_task", { task_id: button.dataset.completeVerification, evidence_url: form.evidence_url.value, notes: form.notes.value }); modal.close(); toast("LIVE record confirmed.", "success"); await renderVerification(content, profile); } catch (error) { toast(error.message, "error", 6000); } });
  }));
}

async function renderOrgChart(content, profile) {
  const [profiles, departments] = await Promise.all([loadProfiles(), db.list("departments", { order: "sort_order", ascending: true }).catch(() => [])]);
  const rankGroups = [
    ["Executive command", ["president","vice_president"]],
    ["Senior command", ["general","admiral"]],
    ["Command", ["vice_admiral","rear_admiral","brigadier_general"]],
    ["Officers", ["officer"]],
    ["Enlisted", ["enlisted"]]
  ];
  content.innerHTML = `${pageHero("Organisation chart","Ranks show command authority. Admin, Quartermaster and Treasurer remain concurrent appointments rather than replacing rank.")}
    <section class="card pad page-section">${header("Command structure","The website groups nine ranks into five practical permission tiers.")}<div class="org-chart">${rankGroups.map(([label, ranks]) => `<div class="org-tier"><h3>${escapeHtml(label)}</h3><div class="member-grid compact">${profiles.filter((member) => ranks.includes(member.rank) && member.status === "active").map((member) => `<article class="org-person"><strong>${escapeHtml(member.display_name)}</strong><span>${escapeHtml(rankLabel(member.rank))}</span><small>${escapeHtml(member.rsi_handle || "No RSI handle")}</small><div class="button-row">${(member.roles || []).map((role) => `<span class="pill amber">${escapeHtml(roleLabel(role))}</span>`).join("")}${member.membership_stage === "probationary" ? '<span class="pill amber">Probationary</span>' : ""}</div></article>`).join("") || `<p class="muted">No active members in this tier.</p>`}</div></div>`).join("")}</div></section>
    <section class="card pad page-section">${header("Departments","Members can belong to several departments while retaining their organisation rank and appointments.")}<div class="grid cols-3">${departments.filter(d=>d.enabled!==false).map((department) => { const members = profiles.filter((member) => (member.departments || []).some((item) => item.id === department.id)); return `<article class="card inset-card"><h3>${escapeHtml(department.name)}</h3><p>${escapeHtml(department.description || "")}</p><div class="list">${members.map((member) => `<div class="list-item"><div><strong>${escapeHtml(member.display_name)}</strong><small>${escapeHtml((member.departments || []).find((item) => item.id === department.id)?.department_role || "member")}</small></div><span class="pill cyan">${escapeHtml(rankLabel(member.rank))}</span></div>`).join("") || `<small class="muted">No assigned members.</small>`}</div></article>`; }).join("")}</div></section>`;
}

async function renderKnowledgeBase(content, profile) {
  const articles = await db.list("knowledge_articles", { order: "updated_at", ascending: false }).catch(() => []);
  const canEdit = Boolean(profile.capabilities?.manage_knowledge);
  content.innerHTML = `${pageHero("Organisation knowledge base","Versioned Free Navy procedures, approved loadouts, induction material and LIVE operational guides.")}
    ${header("Guides and procedures",`${articles.length} accessible article${articles.length === 1 ? "" : "s"}.`,canEdit ? '<button id="add-knowledge-article" class="button primary">New article</button>' : "")}
    <div class="toolbar"><input id="knowledge-filter" type="search" placeholder="Search guides…"><select id="knowledge-category"><option value="">All categories</option>${[...new Set(articles.map(a=>a.category).filter(Boolean))].sort().map(category=>`<option>${escapeHtml(category)}</option>`).join("")}</select></div>
    <div id="knowledge-article-grid" class="grid cols-3"></div>`;
  const renderArticles = () => {
    const q = $("#knowledge-filter").value.toLowerCase(); const category = $("#knowledge-category").value;
    const filtered = articles.filter((article) => (!category || article.category === category) && (!q || JSON.stringify(article).toLowerCase().includes(q)));
    $("#knowledge-article-grid").innerHTML = filtered.map((article) => `<article class="card pad knowledge-card"><div class="card-topline"><div><p class="eyebrow">${escapeHtml(article.category)}</p><h3>${escapeHtml(article.title)}</h3></div>${pill(article.status)}</div><p>${escapeHtml(article.summary || "")}</p><small class="muted">Revision ${article.current_revision} · ${escapeHtml(titleCase(article.audience))} · Updated ${formatDate(article.updated_at)}</small><div class="button-row"><button class="button small" data-read-article="${article.id}">Read</button>${canEdit ? `<button class="button small ghost" data-edit-article="${article.id}">Edit</button>` : ""}</div></article>`).join("") || emptyState("No matching articles","Try another category or create the first guide.");
    $$('[data-read-article]').forEach((button) => button.addEventListener("click", () => { const article = articles.find(a=>a.id===button.dataset.readArticle); openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">${escapeHtml(article.category)}</p><h2>${escapeHtml(article.title)}</h2><p class="fine-print">Revision ${article.current_revision} · ${escapeHtml(titleCase(article.audience))}</p><div class="article-body">${escapeHtml(article.body || "").replaceAll("\n","<br>")}</div>`, true); }));
    $$('[data-edit-article]').forEach((button) => button.addEventListener("click", () => articleForm(articles.find(a=>a.id===button.dataset.editArticle))));
  };
  const articleForm = (existing = null) => {
    const modal = openModal(`<button class="icon-button close-button" data-close-modal>×</button><p class="eyebrow">KNOWLEDGE BASE</p><h2>${existing ? "Edit" : "Create"} article</h2><form id="article-form" class="stack-form"><label>Title<input name="title" value="${escapeHtml(existing?.title || "")}" required></label><label>Slug<input name="slug" value="${escapeHtml(existing?.slug || "")}" placeholder="mining-standard-operating-procedure"></label><label>Category<input name="category" value="${escapeHtml(existing?.category || "General")}" required></label><label>Summary<textarea name="summary" rows="2">${escapeHtml(existing?.summary || "")}</textarea></label><label>Body<textarea name="body" rows="14" required>${escapeHtml(existing?.body || "")}</textarea></label><div class="grid cols-2"><label>Status<select name="status">${["draft","review","published","archived"].map(value=>`<option value="${value}" ${existing?.status===value ? "selected" : ""}>${titleCase(value)}</option>`).join("")}</select></label><label>Audience<select name="audience">${["members","officers","command"].map(value=>`<option value="${value}" ${existing?.audience===value ? "selected" : ""}>${titleCase(value)}</option>`).join("")}</select></label></div><label>Change note<input name="change_note" placeholder="What changed in this revision?"></label><button class="button primary">Save article</button></form>`, true);
    $("#article-form",modal.card).addEventListener("submit", async (event) => { event.preventDefault(); const form = event.currentTarget; const slug = (form.slug.value || form.title.value).toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,""); try { await db.rpc("save_knowledge_article", { article_id: existing?.id || null, slug, title: form.title.value, category: form.category.value, summary: form.summary.value, body: form.body.value, status: form.status.value, audience: form.audience.value, change_note: form.change_note.value }); modal.close(); toast("Knowledge article saved with revision history.","success"); await renderKnowledgeBase(content,profile); } catch(error){ toast(error.message,"error",6000); } });
  };
  $("#add-knowledge-article")?.addEventListener("click",()=>articleForm());
  $("#knowledge-filter").addEventListener("input",renderArticles); $("#knowledge-category").addEventListener("change",renderArticles); renderArticles();
}
